function renderWeeklyHeatmapChart(visits, trainings, observations) {
  destroyChart('heatmapChart');
  const canvas = document.getElementById('chartWeeklyHeatmap');
  if (!canvas) return;

  const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const dayCounts = [0, 0, 0, 0, 0, 0, 0];

  [...visits, ...trainings, ...observations].forEach(item => {
    const d = new Date(item.date);
    if (!isNaN(d)) dayCounts[d.getDay()]++;
  });

  if (dayCounts.every(c => c === 0)) {
    canvas.style.display = 'none';
    if (!canvas.parentElement.querySelector('.empty-state')) canvas.insertAdjacentHTML('afterend', '<div class="empty-state small"><i class="fas fa-calendar"></i><p>No activities in this period</p></div>');
    return;
  }
  canvas.style.display = '';
  { const e = canvas.parentElement.querySelector('.empty-state'); if (e) e.remove(); }

  const maxVal = Math.max(...dayCounts);
  const colors = dayCounts.map(c => {
    const intensity = maxVal > 0 ? c / maxVal : 0;
    return `rgba(245, 158, 11, ${0.15 + intensity * 0.75})`;
  });

  analyticsCharts.heatmapChart = new Chart(canvas, {
    type: 'bar',
    data: {
      labels: dayNames,
      datasets: [{ label: 'Activities', data: dayCounts, backgroundColor: colors, borderRadius: 8, barThickness: 36 }]
    },
    options: {
      responsive: true, maintainAspectRatio: false,
      plugins: { legend: { display: false } },
      scales: {
        x: { ticks: { color: '#9ca3b8', font: { weight: '600' } }, grid: { display: false } },
        y: { beginAtZero: true, ticks: { color: '#6b7280', precision: 0 }, grid: { color: 'rgba(255,255,255,0.04)' } }
      }
    }
  });
}

function renderActivityTimeline(visits, trainings, observations) {
  const container = document.getElementById('activityTimeline');
  const countEl = document.getElementById('timelineCount');
  if (!container || !countEl) return;

  const items = [
    ...visits.map(v => ({ type: 'visit', icon: 'fa-school', cls: 'tl-visit', title: v.school, detail: v.purpose || '', status: v.status, date: v.date, time: v.createdAt || v.date })),
    ...trainings.map(t => ({ type: 'training', icon: 'fa-chalkboard-teacher', cls: 'tl-training', title: t.title, detail: `${t.attendees || 0} attendees · ${t.duration || 0}h`, status: t.status, date: t.date, time: t.createdAt || t.date })),
    ...observations.map(o => ({ type: 'observation', icon: 'fa-clipboard-check', cls: 'tl-observation', title: `${o.school} ${o.subject}`, detail: o.teacher ? `Teacher: ${o.teacher}` : '', status: '', date: o.date, time: o.createdAt || o.date })),
  ].sort((a, b) => new Date(b.date) - new Date(a.date));

  countEl.textContent = `${items.length} activities`;

  if (items.length === 0) {
    container.innerHTML = '<div class="empty-state small"><i class="fas fa-stream"></i><p>No activities in this period</p></div>';
    return;
  }

  container.innerHTML = items.map(item => {
    const d = new Date(item.date);
    const dateStr = d.toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' });
    return `<div class="timeline-item">
 <div class="timeline-dot ${item.cls}"><i class="fas ${item.icon}"></i></div>
 <div class="timeline-content">
 <div class="timeline-header">
 <strong>${escapeHtml(item.title)}</strong>
 ${item.status ? `<span class="badge badge-${item.status}">${item.status}</span>` : ''}
 </div>
 ${item.detail ? `<p class="timeline-detail">${escapeHtml(item.detail)}</p>` : ''}
 <span class="timeline-date">${dateStr}</span>
 </div>
 </div>`;
  }).join('');
}

// ===== FOLLOW-UP TRACKER =====
const ACTION_CLOSURE_SLA_DAYS = {
  visit: 14,
  observation: 10,
  meeting: 7
};

const ACTION_CLOSURE_SOURCE_LABELS = {
  visit: 'Visit',
  observation: 'Observation',
  meeting: 'Meeting'
};

function isDoneFollowupStatus(status) {
  const s = (status || '').toString().trim().toLowerCase();
  return s === 'done' || s === 'completed' || s === 'closed' || s === 'resolved';
}

function normalizeDateOnly(dateValue) {
  if (!dateValue) return '';
  const v = String(dateValue).trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(v)) return v;
  const d = new Date(v);
  if (isNaN(d.getTime())) return '';
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
}

function dateOnlyToMs(dateValue) {
  const v = normalizeDateOnly(dateValue);
  if (!v) return null;
  const d = new Date(v + 'T00:00:00');
  return isNaN(d.getTime()) ? null : d.getTime();
}

function addDaysToDate(dateValue, days) {
  const ms = dateOnlyToMs(dateValue) ?? Date.now();
  const d = new Date(ms);
  d.setDate(d.getDate() + days);
  return normalizeDateOnly(d);
}

function normalizeText(value) {
  return (value || '').toString().trim().toLowerCase();
}

function getDefaultFollowupOwner() {
  const profile = DB.get('userProfile') || {};
  return (profile.name || 'Resource Person').toString().trim() || 'Resource Person';
}

function getFollowupHistory(entry) {
  if (!entry) return [];
  if (!Array.isArray(entry.history)) entry.history = [];
  return entry.history;
}

function addFollowupHistory(entry, type, message, meta = null) {
  if (!entry) return false;
  const history = getFollowupHistory(entry);
  const nowIso = new Date().toISOString();
  const payload = {
    ts: nowIso,
    type: type || 'update',
    message: message || 'Action updated'
  };
  if (meta && typeof meta === 'object') payload.meta = meta;

  const last = history[history.length - 1];
  if (last && last.type === payload.type && last.message === payload.message) return false;

  history.push(payload);
  if (history.length > 40) entry.history = history.slice(-40);
  return true;
}

function formatFollowupHistoryTime(ts) {
  if (!ts) return '';
  const d = new Date(ts);
  if (isNaN(d.getTime())) return '';
  return d.toLocaleString('en-IN', {
    day: '2-digit',
    month: 'short',
    hour: '2-digit',
    minute: '2-digit'
  });
}

function collectFollowupItems() {
  const visits = DB.get('visits') || [];
  const observations = DB.get('observations') || [];
  const meetings = DB.get('meetings') || [];
  const items = [];

  visits.forEach(v => {
    if (v.followUp && v.followUp.trim()) {
      items.push({
        id: v.id,
        source: 'visit',
        sourceId: v.id,
        school: v.school || '',
        block: v.block || '',
        cluster: v.cluster || '',
        date: normalizeDateOnly(v.date),
        text: v.followUp,
        icon: 'fa-school',
        cls: 'followup-visit'
      });
    }
  });

  observations.forEach(o => {
    if (o.suggestions && o.suggestions.trim()) {
      items.push({
        id: o.id,
        source: 'observation',
        sourceId: o.id,
        school: o.school || '',
        block: o.block || '',
        cluster: o.cluster || '',
        date: normalizeDateOnly(o.date),
        text: o.suggestions,
        teacher: o.teacher || '',
        icon: 'fa-clipboard-check',
        cls: 'followup-obs'
      });
    }
  });

  meetings.forEach(m => {
    (m.actionItems || []).forEach((a, i) => {
      if (a.text && a.text.trim()) {
        items.push({
          id: `meeting_${m.id}_${i}`,
          source: 'meeting',
          sourceId: m.id,
          school: m.title || 'Meeting',
          block: '',
          cluster: '',
          date: normalizeDateOnly(m.date),
          text: a.text,
          assignee: a.assignee || '',
          icon: 'fa-handshake',
          cls: 'followup-meeting'
        });
      }
    });
  });

  // Manual follow-ups
  const manuals = DB.get('manualFollowups') || [];
  manuals.forEach(m => {
    if (m.text && m.text.trim()) {
      items.push({
        id: m.id,
        source: 'manual',
        sourceId: m.id,
        school: m.school || '',
        block: m.block || '',
        cluster: m.cluster || '',
        date: normalizeDateOnly(m.date || m.createdAt),
        text: m.text,
        icon: 'fa-pen-to-square',
        cls: 'followup-manual'
      });
    }
  });

  return items;
}

function upsertFollowupLifecycle(statusList, item) {
  let entry = statusList.find(f => f.id === item.id);
  let created = false;
  let changed = false;
  let historyBefore = 0;

  if (!entry) {
    entry = { id: item.id, done: false };
    statusList.push(entry);
    created = true;
    changed = true;
    addFollowupHistory(
      entry,
      'created',
      `Action created from ${ACTION_CLOSURE_SOURCE_LABELS[item.source] || 'Action'}`
    );
  }
  historyBefore = Array.isArray(entry.history) ? entry.history.length : 0;

  const doneFromStatus = isDoneFollowupStatus(entry.status);
  if (typeof entry.done !== 'boolean') {
    entry.done = doneFromStatus;
    changed = true;
  } else if (!entry.done && doneFromStatus) {
    entry.done = true;
    changed = true;
  }

  const normalizedStatus = entry.done ? 'done' : 'pending';
  if (entry.status !== normalizedStatus) {
    entry.status = normalizedStatus;
    changed = true;
  }

  const defaultOwner = (item.assignee || '').trim() || getDefaultFollowupOwner();
  const defaultDueDate = addDaysToDate(item.date, ACTION_CLOSURE_SLA_DAYS[item.source] || 14);

  const patchIfEmpty = (field, value) => {
    if ((entry[field] === undefined || entry[field] === null || entry[field] === '') && value !== undefined && value !== null && value !== '') {
      entry[field] = value;
      changed = true;
    }
  };

  patchIfEmpty('source', item.source);
  patchIfEmpty('sourceId', item.sourceId || item.id);
  patchIfEmpty('school', item.school || '');
  patchIfEmpty('block', item.block || '');
  patchIfEmpty('cluster', item.cluster || '');
  patchIfEmpty('text', item.text || '');
  patchIfEmpty('sourceDate', item.date || '');
  const hadOwner = !!entry.owner;
  const hadDueDate = !!entry.dueDate;
  patchIfEmpty('owner', defaultOwner);
  patchIfEmpty('dueDate', defaultDueDate);
  patchIfEmpty('priority', item.source === 'meeting' ? 'medium' : 'high');
  patchIfEmpty('createdAt', new Date().toISOString());

  if (entry.done && !entry.closedAt) {
    entry.closedAt = new Date().toISOString();
    changed = true;
  }

  if (!entry.done && entry.status !== 'pending') {
    entry.status = 'pending';
    changed = true;
  }

  if (!hadOwner && entry.owner) {
    addFollowupHistory(entry, 'owner-set', `Owner assigned to ${entry.owner}`);
  }
  if (!hadDueDate && entry.dueDate) {
    addFollowupHistory(entry, 'sla-set', `SLA set for ${entry.dueDate}`);
  }
  if (getFollowupHistory(entry).length === 0) {
    addFollowupHistory(entry, 'created', `Action tracked from ${ACTION_CLOSURE_SOURCE_LABELS[item.source] || 'Action'}`);
  }
  if ((Array.isArray(entry.history) ? entry.history.length : 0) !== historyBefore) {
    changed = true;
  }

  return { entry, changed, created };
}

function getActionClosureEvidenceCandidates(item) {
  const sourceMs = dateOnlyToMs(item.date);
  if (!sourceMs) return [];

  const schoolNorm = normalizeText(item.school);
  const blockNorm = normalizeText(item.block);
  const visits = DB.get('visits') || [];
  const observations = DB.get('observations') || [];
  const trainings = DB.get('trainings') || [];
  const evidence = [];

  observations.forEach(o => {
    if (!o.id || o.id === item.sourceId || normalizeText(o.school) !== schoolNorm) return;
    const ms = dateOnlyToMs(o.date);
    if (ms === null || ms < sourceMs) return;
    evidence.push({
      _ms: ms,
      confidence: 3,
      type: 're-observation',
      sourceLabel: 'Observation',
      refId: o.id,
      date: normalizeDateOnly(o.date),
      label: `Re-observation at ${o.school || 'school'} on ${new Date(ms).toLocaleDateString('en-IN')}`,
      summary: o.teacher ? `Teacher: ${o.teacher}` : ''
    });
  });

  visits.forEach(v => {
    if (!v.id || v.id === item.sourceId) return;
    if ((v.status || '').toLowerCase() !== 'completed') return;
    if (normalizeText(v.school) !== schoolNorm) return;
    const ms = dateOnlyToMs(v.date);
    if (ms === null || ms < sourceMs) return;
    evidence.push({
      _ms: ms,
      confidence: 2,
      type: 'follow-up-visit',
      sourceLabel: 'Visit',
      refId: v.id,
      date: normalizeDateOnly(v.date),
      label: `Follow-up visit at ${v.school || 'school'} on ${new Date(ms).toLocaleDateString('en-IN')}`,
      summary: v.purpose ? `Purpose: ${v.purpose}` : ''
    });
  });

  trainings.forEach(t => {
    if (!t.id) return;
    if ((t.status || '').toLowerCase() !== 'completed') return;
    const ms = dateOnlyToMs(t.date);
    if (ms === null || ms < sourceMs) return;
    const searchFields = [t.title, t.venue, t.notes, t.target].map(normalizeText);
    const schoolHit = schoolNorm && searchFields.some(s => s.includes(schoolNorm));
    const blockHit = blockNorm && searchFields.some(s => s.includes(blockNorm));
    if (!schoolHit && !blockHit) return;
    evidence.push({
      _ms: ms,
      confidence: 1,
      type: 'training-support',
      sourceLabel: 'Training',
      refId: t.id,
      date: normalizeDateOnly(t.date),
      label: `Training support "${(t.title || 'Training').slice(0, 55)}" on ${new Date(ms).toLocaleDateString('en-IN')}`,
      summary: `${t.attendees || 0} attendees${t.venue ? ` · ${t.venue}` : ''}`
    });
  });

  if (evidence.length === 0) return [];
  evidence.sort((a, b) => {
    if (b.confidence !== a.confidence) return b.confidence - a.confidence;
    return (a._ms || 0) - (b._ms || 0);
  });
  return evidence.map(e => {
    const { _ms, ...rest } = e;
    return rest;
  });
}

function findActionClosureEvidence(item) {
  const candidates = getActionClosureEvidenceCandidates(item);
  return candidates.length > 0 ? candidates[0] : null;
}

function syncActionClosureRecords(items, options = {}) {
  const autoClose = !!options.autoClose;
  const statusList = DB.get('followupStatus') || [];
  let changed = false;
  let createdCount = 0;
  let autoClosedCount = 0;

  items.forEach(item => {
    const synced = upsertFollowupLifecycle(statusList, item);
    if (synced.changed) changed = true;
    if (synced.created) createdCount++;

    const entry = synced.entry;
    if (!autoClose || entry.done) return;

    const ev = findActionClosureEvidence(item);
    if (!ev) return;

    entry.done = true;
    entry.status = 'done';
    entry.closedAt = new Date().toISOString();
    entry.closureType = ev.type;
    entry.closureRefId = ev.refId;
    entry.closureDate = ev.date;
    entry.closureLabel = ev.label;
    entry.closureMode = 'auto';
    entry.updatedAt = new Date().toISOString();
    addFollowupHistory(entry, 'auto-closed', `Auto-closed via ${ev.label}`, { closureType: ev.type, refId: ev.refId });
    autoClosedCount++;
    changed = true;
  });

  if (changed) DB.set('followupStatus', statusList);
  return { statusList, createdCount, autoClosedCount, changed };
}

function runActionClosureEngine() {
  const items = collectFollowupItems();
  const result = syncActionClosureRecords(items, { autoClose: true });
  renderFollowups();
  const message = `Action Closure Sync: ${result.autoClosedCount} auto-closed, ${result.createdCount} lifecycle records updated`;
  showToast(message, result.autoClosedCount > 0 ? 'success' : 'info', 2600);
}

let _followupEvidenceContext = null;

function renderFollowupEvidencePicker() {
  const listEl = document.getElementById('followupEvidenceList');
  const btn = document.getElementById('followupEvidenceConfirmBtn');
  if (!listEl || !btn) return;

  const ctx = _followupEvidenceContext;
  if (!ctx) {
    listEl.innerHTML = '';
    btn.disabled = true;
    return;
  }

  if (!ctx.candidates || ctx.candidates.length === 0) {
    listEl.innerHTML = `<div class="followup-evidence-empty"><i class="fas fa-search"></i> No evidence candidates found for this action yet.</div>`;
    btn.disabled = true;
    return;
  }

  listEl.innerHTML = ctx.candidates.map((c, idx) => `
 <label class="followup-evidence-item ${ctx.selectedIndex === idx ? 'active' : ''}">
 <input type="radio" name="followupEvidenceChoice" ${ctx.selectedIndex === idx ? 'checked' : ''} onchange="selectFollowupEvidenceCandidate(${idx})">
 <div class="followup-evidence-content">
 <div class="followup-evidence-top">
 <span class="followup-evidence-type">${escapeHtml(c.sourceLabel || 'Evidence')}</span>
 <span class="followup-evidence-date">${escapeHtml(c.date || '')}</span>
 </div>
 <div class="followup-evidence-title">${escapeHtml(c.label || 'Evidence')}</div>
 ${c.summary ? `<div class="followup-evidence-summary">${escapeHtml(c.summary)}</div>` : ''}
 </div>
 </label>
 `).join('');

  btn.disabled = ctx.selectedIndex === null || ctx.selectedIndex < 0;
}

function openFollowupEvidencePicker(id) {
  const items = collectFollowupItems();
  const item = items.find(f => f.id === id);
  if (!item) {
    showToast('Action not found', 'error');
    return;
  }

  const statusList = DB.get('followupStatus') || [];
  const synced = upsertFollowupLifecycle(statusList, item);
  if (synced.changed) DB.set('followupStatus', statusList);

  const candidates = getActionClosureEvidenceCandidates(item);
  _followupEvidenceContext = {
    id,
    item,
    candidates,
    selectedIndex: candidates.length > 0 ? 0 : null
  };

  const metaEl = document.getElementById('followupEvidenceMeta');
  if (metaEl) {
    const sourceLabel = ACTION_CLOSURE_SOURCE_LABELS[item.source] || 'Action';
    metaEl.innerHTML = `
 <div class="followup-evidence-meta-source"><i class="fas ${item.icon || 'fa-link'}"></i> ${escapeHtml(sourceLabel)} · ${escapeHtml(item.school || 'Unknown')}</div>
 <div class="followup-evidence-meta-text">${escapeHtml(item.text || '')}</div>
 `;
  }

  renderFollowupEvidencePicker();
  openModal('followupEvidenceModal');
}

function selectFollowupEvidenceCandidate(index) {
  if (!_followupEvidenceContext) return;
  _followupEvidenceContext.selectedIndex = index;
  renderFollowupEvidencePicker();
}

function applyFollowupEvidenceSelection() {
  const ctx = _followupEvidenceContext;
  if (!ctx) return;
  if (!ctx.candidates || ctx.candidates.length === 0 || ctx.selectedIndex === null || ctx.selectedIndex < 0) {
    showToast('Please select evidence to link', 'warning');
    return;
  }

  const selected = ctx.candidates[ctx.selectedIndex];
  const statusList = DB.get('followupStatus') || [];
  let entry = statusList.find(f => f.id === ctx.id);
  if (!entry) {
    entry = upsertFollowupLifecycle(statusList, ctx.item).entry;
  }

  entry.done = true;
  entry.status = 'done';
  entry.closedAt = new Date().toISOString();
  entry.closureType = selected.type;
  entry.closureRefId = selected.refId;
  entry.closureDate = selected.date;
  entry.closureLabel = selected.label;
  entry.closureMode = 'manual-picker';
  entry.updatedAt = new Date().toISOString();
  addFollowupHistory(entry, 'linked-picker', `Evidence selected: ${selected.label}`, { closureType: selected.type, refId: selected.refId });

  DB.set('followupStatus', statusList);
  closeFollowupEvidenceModal();
  renderFollowups();
  showToast('Closure evidence linked', 'success');
}

function closeFollowupEvidenceModal() {
  _followupEvidenceContext = null;
  const metaEl = document.getElementById('followupEvidenceMeta');
  const listEl = document.getElementById('followupEvidenceList');
  const btn = document.getElementById('followupEvidenceConfirmBtn');
  if (metaEl) metaEl.innerHTML = '';
  if (listEl) listEl.innerHTML = '';
  if (btn) btn.disabled = true;
  closeModal('followupEvidenceModal');
}

function setFollowupOwner(id) {
  const statusList = DB.get('followupStatus') || [];
  let entry = statusList.find(f => f.id === id);
  if (!entry) {
    const item = collectFollowupItems().find(f => f.id === id);
    if (!item) return;
    entry = upsertFollowupLifecycle(statusList, item).entry;
    DB.set('followupStatus', statusList);
  }
  const currentOwner = (entry.owner || '').trim() || getDefaultFollowupOwner();
  _openFuQuickModal({
    type: 'owner',
    id,
    title: 'Assign Owner',
    icon: 'fa-user-pen',
    label: 'Action Owner',
    placeholder: 'Enter name...',
    value: currentOwner
  });
}

let _fuCalTargetId = null;

function setFollowupDueDate(id) {
  const statusList = DB.get('followupStatus') || [];
  let entry = statusList.find(f => f.id === id);
  if (!entry) {
    const item = collectFollowupItems().find(f => f.id === id);
    if (!item) { showToast('Follow-up not found', 'error'); return; }
    entry = upsertFollowupLifecycle(statusList, item).entry;
    DB.set('followupStatus', statusList);
  }
  _fuCalTargetId = id;
  const currentDue = normalizeDateOnly(entry.dueDate) || '';
  const seed = currentDue ? new Date(currentDue + 'T00:00:00') : new Date();
  _fuCalYear = seed.getFullYear();
  _fuCalMonth = seed.getMonth();
  const di = document.getElementById('fuQmDateInput');
  if (di) di.value = currentDue || '';
  const banner = document.getElementById('fuCalSelectedBanner');
  if (banner) {
    if (currentDue) {
      banner.textContent = seed.toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' });
      banner.classList.add('fu-cal-modal-banner-set');
    } else {
      banner.textContent = 'No date selected';
      banner.classList.remove('fu-cal-modal-banner-set');
    }
  }
  const slaSource = (typeof ACTION_CLOSURE_SLA_DAYS !== 'undefined' && ACTION_CLOSURE_SLA_DAYS[entry.source]) || 14;
  const hintEl = document.getElementById('fuCalHint');
  if (hintEl) hintEl.textContent = 'Default SLA: ' + slaSource + ' days from source date';
  fuCalRender();
  document.getElementById('fuCalModal').style.display = 'flex';
}

let _fuCalYear = new Date().getFullYear(), _fuCalMonth = new Date().getMonth();

function fuCalMove(dir) {
  _fuCalMonth += dir;
  if (_fuCalMonth > 11) { _fuCalMonth = 0; _fuCalYear++; }
  if (_fuCalMonth < 0) { _fuCalMonth = 11; _fuCalYear--; }
  fuCalRender();
}

function fuCalOpen() {
  fuCalRender();
  const modal = document.getElementById('fuCalModal');
  if (modal) modal.style.display = 'flex';
}

function fuCalClose() {
  const modal = document.getElementById('fuCalModal');
  if (modal) modal.style.display = 'none';
  _fuCalTargetId = null;
}

function fuCalConfirm() {
  const val = (document.getElementById('fuQmDateInput') || {}).value;
  if (!val) { showToast('Please select a date.', 'info'); return; }
  if (_fuCalTargetId) {
    const statusList = DB.get('followupStatus') || [];
    const entry = statusList.find(f => f.id === _fuCalTargetId);
    if (entry) {
      entry.dueDate = val;
      entry.updatedAt = new Date().toISOString();
      addFollowupHistory(entry, 'sla-updated', 'SLA updated to ' + val);
      DB.set('followupStatus', statusList);
      showToast('SLA date updated', 'success');
      renderFollowups();
    }
  }
  fuCalClose();
}

function fuCalSelect(dateStr) {
  const di = document.getElementById('fuQmDateInput');
  if (di) di.value = dateStr;
  const d = new Date(dateStr + 'T00:00:00');
  const formatted = d.toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' });
  const banner = document.getElementById('fuCalSelectedBanner');
  if (banner) { banner.textContent = formatted; banner.classList.add('fu-cal-modal-banner-set'); }
  fuCalRender();
}

function fuCalRender() {
  const monthNames = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];
  const lbl = document.getElementById('fuCalMonthYear');
  if (lbl) lbl.textContent = monthNames[_fuCalMonth] + ' ' + _fuCalYear;
  const grid = document.getElementById('fuCalDays');
  if (!grid) return;
  const today = normalizeDateOnly(new Date());
  const selected = (document.getElementById('fuQmDateInput') || {}).value || '';
  // Sync banner inside calendar modal
  const banner = document.getElementById('fuCalSelectedBanner');
  if (banner) {
    if (selected) {
      const sd = new Date(selected + 'T00:00:00');
      banner.textContent = sd.toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' });
      banner.classList.add('fu-cal-modal-banner-set');
    } else {
      banner.textContent = 'No date selected';
      banner.classList.remove('fu-cal-modal-banner-set');
    }
  }
  const daysInMonth = new Date(_fuCalYear, _fuCalMonth + 1, 0).getDate();
  const firstDay = new Date(_fuCalYear, _fuCalMonth, 1).getDay();
  let html = '';
  for (let i = 0; i < firstDay; i++) html += '<div class="fu-cal-empty"></div>';
  for (let d = 1; d <= daysInMonth; d++) {
    const ds = `${_fuCalYear}-${String(_fuCalMonth + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
    const cls = ['fu-cal-day', ds === today ? 'fu-cal-today' : '', ds === selected ? 'fu-cal-sel' : ''].filter(Boolean).join(' ');
    html += `<button type="button" class="${cls}" onclick="fuCalSelect('${ds}')">${d}</button>`;
  }
  grid.innerHTML = html;
}

function _openFuQuickModal(opts) {
  document.getElementById('fuQmTitle').textContent = opts.title;
  document.getElementById('fuQmIcon').className = 'fas ' + opts.icon;
  document.getElementById('fuQmLabel').textContent = opts.label;
  document.getElementById('fuQmId').value = opts.id;
  document.getElementById('fuQmType').value = opts.type;
  const inp = document.getElementById('fuQmInput');
  const calWrap = document.getElementById('fuCalPicker');
  const hint = document.getElementById('fuQmHint');
  if (opts.type === 'sla') {
    inp.style.display = 'none';
    calWrap.style.display = 'block';
    document.getElementById('fuQmDateInput').value = opts.value || '';
    // Init calendar to current value or today
    const seed = opts.value ? new Date(opts.value + 'T00:00:00') : new Date();
    _fuCalYear = seed.getFullYear();
    _fuCalMonth = seed.getMonth();
    // Update trigger button display
    const disp = document.getElementById('fuCalSelectedDisplay');
    const trig2 = document.getElementById('fuCalTrigger');
    if (disp) {
      if (opts.value) {
        disp.textContent = seed.toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' });
        if (trig2) { trig2.classList.add('fu-cal-trigger-set'); trig2.classList.remove('open'); }
      } else {
        disp.textContent = 'Click to select a date';
        if (trig2) trig2.classList.remove('fu-cal-trigger-set', 'open');
      }
    }
    // Ensure calendar modal is closed when SLA modal opens
    const fuCM = document.getElementById('fuCalModal');
    if (fuCM) fuCM.style.display = 'none';
    hint.textContent = opts.slaHint || '';
    hint.style.display = opts.slaHint ? 'block' : 'none';
    fuCalRender();
  } else {
    inp.style.display = 'block';
    calWrap.style.display = 'none';
    inp.value = opts.value || '';
    inp.placeholder = opts.placeholder || '';
    hint.style.display = 'none';
    setTimeout(() => { inp.focus(); inp.select(); }, 80);
  }
  document.getElementById('fuQuickModal').style.display = 'flex';
}

function closeFuQuickModal() {
  document.getElementById('fuQuickModal').style.display = 'none';
}

function saveFuQuickModal() {
  const id = document.getElementById('fuQmId').value;
  const type = document.getElementById('fuQmType').value;
  const statusList = DB.get('followupStatus') || [];
  const entry = statusList.find(f => f.id === id);
  if (!entry) { closeFuQuickModal(); return; }

  if (type === 'sla') {
    const val = document.getElementById('fuQmDateInput').value;
    const dueDate = normalizeDateOnly(val);
    if (!dueDate) { showToast('Please select a valid date.', 'error'); return; }
    entry.dueDate = dueDate;
    entry.updatedAt = new Date().toISOString();
    addFollowupHistory(entry, 'sla-updated', `SLA updated to ${dueDate}`);
    showToast('SLA date updated', 'success');
  } else {
    const owner = document.getElementById('fuQmInput').value.trim();
    if (!owner) { showToast('Owner cannot be empty.', 'error'); return; }
    entry.owner = owner;
    entry.updatedAt = new Date().toISOString();
    addFollowupHistory(entry, 'owner-updated', `Owner changed to ${owner}`);
    showToast('Owner updated', 'success');
  }
  DB.set('followupStatus', statusList);
  closeFuQuickModal();
  renderFollowups();
}

function linkFollowupEvidence(id) {
  openFollowupEvidencePicker(id);
}

// ===== FOLLOW-UP TRACKER ENHANCED HELPERS =====

function autoDetectPriority(text) {
  const t = (text || '').toLowerCase();
  const highKw = ['urgent', 'critical', 'immediately', 'failing', 'failed', 'serious', 'emergency', 'asap', 'dropout', 'violence', 'danger', 'severe', 'no teacher', 'absent', 'closed school', 'not reporting'];
  const lowKw = ['consider', 'suggest', 'optional', 'try', 'explore', 'might', 'could', 'general', 'routine', 'when possible', 'eventually', 'minor'];
  if (highKw.some(k => t.includes(k))) return 'high';
  if (lowKw.some(k => t.includes(k))) return 'low';
  return 'medium';
}

function _getOrCreateFollowupEntry(id) {
  const statusList = DB.get('followupStatus') || [];
  let entry = statusList.find(f => f.id === id);
  if (!entry) {
    const item = collectFollowupItems().find(f => f.id === id);
    if (!item) return null;
    entry = upsertFollowupLifecycle(statusList, item).entry;
    DB.set('followupStatus', statusList);
  }
  return { statusList, entry };
}

function setFollowupPriority(id, priority) {
  const r = _getOrCreateFollowupEntry(id);
  if (!r) return;
  r.entry.priority = priority;
  r.entry.updatedAt = new Date().toISOString();
  addFollowupHistory(r.entry, 'priority-set', `Priority set to ${priority}`);
  DB.set('followupStatus', r.statusList);
  renderFollowups();
}

function setFollowupRichStatus(id, status) {
  const r = _getOrCreateFollowupEntry(id);
  if (!r) return;
  const prevDone = r.entry.done;
  r.entry.richStatus = status;
  r.entry.done = (status === 'done');
  r.entry.status = status;
  r.entry.updatedAt = new Date().toISOString();
  if (status === 'done' && !prevDone) {
    if (!r.entry.closedAt) r.entry.closedAt = new Date().toISOString();
    if (!r.entry.closureLabel) r.entry.closureLabel = 'Closed manually';
    if (!r.entry.closureType) r.entry.closureType = 'manual';
    if (!r.entry.closureMode) r.entry.closureMode = 'manual';
    if (!r.entry.closureDate) r.entry.closureDate = normalizeDateOnly(new Date());
  } else if (status !== 'done' && prevDone) {
    r.entry.reopenedAt = new Date().toISOString();
  }
  addFollowupHistory(r.entry, 'status-changed', `Status changed to ${status}`);
  DB.set('followupStatus', r.statusList);
  renderFollowups();
  const labels = { pending: 'Marked Pending', 'in-progress': 'In Progress', blocked: 'Marked Blocked', done: 'Completed!' };
  showToast(labels[status] || status, status === 'done' ? 'success' : 'info');
}

function toggleFollowupPin(id) {
  const r = _getOrCreateFollowupEntry(id);
  if (!r) return;
  r.entry.pinned = !r.entry.pinned;
  r.entry.updatedAt = new Date().toISOString();
  DB.set('followupStatus', r.statusList);
  renderFollowups();
  showToast(r.entry.pinned ? 'Follow-up pinned to top' : 'Follow-up unpinned', 'info');
}

let _fuHideTargetId = null;

function hideFollowup(id) {
  _fuHideTargetId = id;
  document.getElementById('fuHideConfirmModal').style.display = 'flex';
}

function cancelHideFollowup() {
  _fuHideTargetId = null;
  document.getElementById('fuHideConfirmModal').style.display = 'none';
}

function confirmHideFollowup() {
  document.getElementById('fuHideConfirmModal').style.display = 'none';
  if (!_fuHideTargetId) return;
  const r = _getOrCreateFollowupEntry(_fuHideTargetId);
  _fuHideTargetId = null;
  if (!r) return;
  r.entry.hidden = true;
  r.entry.updatedAt = new Date().toISOString();
  DB.set('followupStatus', r.statusList);
  renderFollowups();
  showToast('Follow-up hidden. Use the Hidden filter to restore.', 'info');
}

function unhideFollowup(id) {
  const r = _getOrCreateFollowupEntry(id);
  if (!r) return;
  r.entry.hidden = false;
  r.entry.updatedAt = new Date().toISOString();
  DB.set('followupStatus', r.statusList);
  renderFollowups();
  showToast('Follow-up restored.', 'success');
}

function addFollowupNotePrompt(id) {
  const r = _getOrCreateFollowupEntry(id);
  if (!r) return;
  document.getElementById('fuNoteTargetId').value = id;
  document.getElementById('fuNoteText').value = '';
  document.getElementById('fuNoteModal').style.display = 'flex';
  setTimeout(() => document.getElementById('fuNoteText').focus(), 80);
}

function closeFuNoteModal() {
  document.getElementById('fuNoteModal').style.display = 'none';
}

function saveFuNote() {
  const id = document.getElementById('fuNoteTargetId').value;
  const text = document.getElementById('fuNoteText').value.trim();
  if (!text) { showToast('Note cannot be empty.', 'error'); return; }
  const r = _getOrCreateFollowupEntry(id);
  if (!r) return;
  if (!Array.isArray(r.entry.notes)) r.entry.notes = [];
  r.entry.notes.push({ id: DB.generateId(), ts: new Date().toISOString(), text });
  r.entry.updatedAt = new Date().toISOString();
  addFollowupHistory(r.entry, 'note-added', 'Note added');
  DB.set('followupStatus', r.statusList);
  closeFuNoteModal();
  renderFollowups();
  showToast('Note added', 'success');
}

function deleteFollowupNote(id, noteId) {
  const r = _getOrCreateFollowupEntry(id);
  if (!r) return;
  r.entry.notes = (r.entry.notes || []).filter(n => n.id !== noteId);
  r.entry.updatedAt = new Date().toISOString();
  DB.set('followupStatus', r.statusList);
  renderFollowups();
}

let _followupView = 'list';
function setFollowupView(view) {
  _followupView = view;
  document.getElementById('fuViewList')?.classList.toggle('active', view === 'list');
  document.getElementById('fuViewKanban')?.classList.toggle('active', view === 'kanban');
  renderFollowups();
}

function addManualFollowup() {
  document.getElementById('mfText').value = '';
  document.getElementById('mfSchool').value = '';
  document.getElementById('mfBlock').value = '';
  document.getElementById('mfPriority').value = 'medium';
  document.getElementById('mfDueDate').value = '';
  document.getElementById('mfOwner').value = getDefaultFollowupOwner();
  document.getElementById('mfEditId').value = '';
  document.getElementById('mfModalTitle').textContent = 'Add Follow-up';
  document.getElementById('manualFollowupModal').style.display = 'flex';
}

function closeManualFollowupModal() {
  document.getElementById('manualFollowupModal').style.display = 'none';
}

function saveManualFollowup() {
  const text = document.getElementById('mfText').value.trim();
  if (!text) { showToast('Please enter follow-up text.', 'error'); return; }
  const manuals = DB.get('manualFollowups') || [];
  const editId = document.getElementById('mfEditId').value;
  const owner = document.getElementById('mfOwner').value.trim() || getDefaultFollowupOwner();
  const dueDate = document.getElementById('mfDueDate').value;
  const priority = document.getElementById('mfPriority').value;
  const school = document.getElementById('mfSchool').value.trim();
  const block = document.getElementById('mfBlock').value.trim();

  let savedId = editId;
  if (editId) {
    const item = manuals.find(m => m.id === editId);
    if (item) { item.text = text; item.school = school; item.block = block; item.updatedAt = new Date().toISOString(); }
  } else {
    savedId = DB.generateId();
    manuals.push({ id: savedId, text, school, block, cluster: '', date: normalizeDateOnly(new Date()), source: 'manual', createdAt: new Date().toISOString() });
  }
  DB.set('manualFollowups', manuals);

  // Save priority/owner/dueDate to followupStatus
  const statusList = DB.get('followupStatus') || [];
  let entry = statusList.find(f => f.id === savedId);
  if (!entry) { entry = { id: savedId, done: false }; statusList.push(entry); addFollowupHistory(entry, 'created', 'Manual follow-up created'); }
  entry.priority = priority;
  entry.owner = owner;
  if (dueDate) entry.dueDate = dueDate;
  entry.source = 'manual';
  entry.richStatus = entry.richStatus || 'pending';
  entry.status = entry.status || 'pending';
  entry.updatedAt = new Date().toISOString();
  DB.set('followupStatus', statusList);

  closeManualFollowupModal();
  renderFollowups();
  showToast(editId ? 'Follow-up updated!' : 'Follow-up added!', 'success');
}

function editManualFollowup(id) {
  const manuals = DB.get('manualFollowups') || [];
  const item = manuals.find(m => m.id === id);
  if (!item) return;
  const statusList = DB.get('followupStatus') || [];
  const entry = statusList.find(f => f.id === id) || {};
  document.getElementById('mfEditId').value = id;
  document.getElementById('mfText').value = item.text || '';
  document.getElementById('mfSchool').value = item.school || '';
  document.getElementById('mfBlock').value = item.block || '';
  document.getElementById('mfPriority').value = entry.priority || 'medium';
  document.getElementById('mfDueDate').value = entry.dueDate || '';
  document.getElementById('mfOwner').value = entry.owner || getDefaultFollowupOwner();
  document.getElementById('mfModalTitle').textContent = 'Edit Follow-up';
  document.getElementById('manualFollowupModal').style.display = 'flex';
}

function deleteManualFollowup(id) {
  if (!confirm('Permanently delete this follow-up?')) return;
  let manuals = DB.get('manualFollowups') || [];
  manuals = manuals.filter(m => m.id !== id);
  DB.set('manualFollowups', manuals);
  let status = DB.get('followupStatus') || [];
  status = status.filter(s => s.id !== id);
  DB.set('followupStatus', status);
  renderFollowups();
  showToast('Follow-up deleted', 'success');
}

function exportFollowupsToExcel() {
  if (typeof XLSX === 'undefined') { showToast('Excel library not loaded', 'error'); return; }
  const followupItems = collectFollowupItems();
  const followupStatus = DB.get('followupStatus') || [];
  const statusById = new Map(followupStatus.map(f => [f.id, f]));
  const rows = followupItems.map(item => {
    const st = statusById.get(item.id) || {};
    return {
      Source: (item.source || '').toUpperCase(),
      School: item.school || '',
      Block: item.block || '',
      Teacher: item.teacher || '',
      'Follow-up Text': item.text || '',
      Date: item.date || '',
      Status: st.richStatus || st.status || (st.done ? 'done' : 'pending'),
      Priority: st.priority || autoDetectPriority(item.text),
      Owner: st.owner || item.assignee || getDefaultFollowupOwner(),
      'Due Date': st.dueDate || '',
      'Closed Date': st.closureDate || '',
      Notes: (st.notes || []).map(n => n.text).join(' | ')
    };
  });
  if (!rows.length) { showToast('No follow-ups to export.', 'info'); return; }
  const wb = XLSX.utils.book_new();
  const ws = XLSX.utils.json_to_sheet(rows);
  XLSX.utils.book_append_sheet(wb, ws, 'Follow-ups');
  XLSX.writeFile(wb, `Follow-ups_${normalizeDateOnly(new Date())}.xlsx`);
  showToast('Follow-ups exported!', 'success');
}

function renderFollowups() {
  const followupItems = collectFollowupItems();
  syncActionClosureRecords(followupItems, { autoClose: false });
  const followupStatus = DB.get('followupStatus') || [];
  const statusById = new Map((followupStatus || []).map(f => [f.id, f]));

  const statusFilter = document.getElementById('followupFilter')?.value || 'pending';
  const sourceFilter = document.getElementById('followupSourceFilter')?.value || 'all';
  const priorityFilter = document.getElementById('followupPriorityFilter')?.value || 'all';
  const groupBy = document.getElementById('followupGroupBy')?.value || 'none';
  const sortBy = document.getElementById('followupSortBy')?.value || 'date-desc';
  const searchQ = (document.getElementById('followupSearch')?.value || '').trim().toLowerCase();

  let followups = followupItems.map(item => {
    const st = statusById.get(item.id) || {};
    const done = !!st.done || st.richStatus === 'done';
    const richStatus = st.richStatus || (done ? 'done' : 'pending');
    const priority = st.priority || autoDetectPriority(item.text);
    return {
      ...item,
      done,
      richStatus,
      priority,
      detectedPriority: autoDetectPriority(item.text),
      pinned: !!st.pinned,
      hidden: !!st.hidden,
      notes: Array.isArray(st.notes) ? st.notes : [],
      owner: st.owner || item.assignee || getDefaultFollowupOwner(),
      dueDate: normalizeDateOnly(st.dueDate),
      sourceDate: normalizeDateOnly(st.sourceDate || item.date),
      closureType: st.closureType || '',
      closureLabel: st.closureLabel || '',
      closureMode: st.closureMode || '',
      closureDate: normalizeDateOnly(st.closureDate),
      history: Array.isArray(st.history) ? st.history.slice() : []
    };
  });

  const todayMs = dateOnlyToMs(new Date());
  followups = followups.map(f => {
    const dueMs = dateOnlyToMs(f.dueDate);
    const sourceMs = dateOnlyToMs(f.sourceDate);
    const daysSinceSource = sourceMs !== null && todayMs !== null ? Math.max(0, Math.floor((todayMs - sourceMs) / 86400000)) : 0;
    const dueInDays = dueMs !== null && todayMs !== null ? Math.ceil((dueMs - todayMs) / 86400000) : null;
    const isOverdue = !f.done && dueInDays !== null && dueInDays < 0;
    const urgency = !f.done && isOverdue ? 'urgent' : !f.done && dueInDays !== null && dueInDays <= 2 ? 'moderate' : '';
    return { ...f, daysSinceSource, dueInDays, isOverdue, urgency };
  });

  // Stats from all unhidden items
  const allV = followups.filter(f => !f.hidden);
  const totalCount = allV.length;
  const doneCount = allV.filter(f => f.done).length;
  const pendingCount = allV.filter(f => f.richStatus === 'pending').length;
  const inProgressCount = allV.filter(f => f.richStatus === 'in-progress').length;
  const blockedCount = allV.filter(f => f.richStatus === 'blocked').length;
  const overdueCount = allV.filter(f => f.isOverdue).length;
  const highPriCount = allV.filter(f => !f.done && f.priority === 'high').length;
  const autoClosedCount = allV.filter(f => f.done && f.closureMode === 'auto').length;
  const completionPct = totalCount > 0 ? Math.round((doneCount / totalCount) * 100) : 0;

  const statsEl = document.getElementById('followupStats');
  if (statsEl) statsEl.innerHTML = `
 <div class="followup-stat-card fsc-pending" onclick="document.getElementById('followupFilter').value='pending';_pageState.followups=1;renderFollowups()" title="Show pending">
 <div class="followup-stat-icon pending"><i class="fas fa-hourglass-half"></i></div>
 <div class="followup-stat-value">${pendingCount}</div>
 <div class="followup-stat-label">Pending</div>
 </div>
 <div class="followup-stat-card fsc-inprog" onclick="document.getElementById('followupFilter').value='active';_pageState.followups=1;renderFollowups()" title="Show in progress">
 <div class="followup-stat-icon inprog"><i class="fas fa-spinner"></i></div>
 <div class="followup-stat-value">${inProgressCount}</div>
 <div class="followup-stat-label">In Progress</div>
 </div>
 <div class="followup-stat-card fsc-blocked" onclick="document.getElementById('followupFilter').value='blocked';_pageState.followups=1;renderFollowups()" title="Show blocked">
 <div class="followup-stat-icon blocked"><i class="fas fa-ban"></i></div>
 <div class="followup-stat-value">${blockedCount}</div>
 <div class="followup-stat-label">Blocked</div>
 </div>
 <div class="followup-stat-card fsc-overdue" onclick="document.getElementById('followupFilter').value='active';_pageState.followups=1;renderFollowups()" title="Show active overdue">
 <div class="followup-stat-icon overdue"><i class="fas fa-triangle-exclamation"></i></div>
 <div class="followup-stat-value">${overdueCount}</div>
 <div class="followup-stat-label">SLA Overdue</div>
 </div>
 <div class="followup-stat-card fsc-high" onclick="document.getElementById('followupPriorityFilter').value='high';document.getElementById('followupFilter').value='active';_pageState.followups=1;renderFollowups()" title="Show high priority">
 <div class="followup-stat-icon high"><i class="fas fa-fire"></i></div>
 <div class="followup-stat-value">${highPriCount}</div>
 <div class="followup-stat-label">High Priority</div>
 </div>
 <div class="followup-stat-card fsc-done" onclick="document.getElementById('followupFilter').value='done';_pageState.followups=1;renderFollowups()" title="Show completed">
 <div class="followup-stat-icon done"><i class="fas fa-check-circle"></i></div>
 <div class="followup-stat-value">${doneCount}</div>
 <div class="followup-stat-label">Completed</div>
 </div>
 <div class="followup-stat-card fsc-auto">
 <div class="followup-stat-icon auto"><i class="fas fa-link"></i></div>
 <div class="followup-stat-value">${autoClosedCount}</div>
 <div class="followup-stat-label">Auto Closed</div>
 </div>
 <div class="followup-stat-card fsc-rate" onclick="document.getElementById('followupFilter').value='all';_pageState.followups=1;renderFollowups()" title="Show all">
 <div class="followup-stat-icon total"><i class="fas fa-list"></i></div>
 <div class="followup-stat-value">${totalCount}</div>
 <div class="followup-stat-label">Total</div>
 </div>
 `;

  // Progress bar
  const pw = document.getElementById('followupProgressWrap');
  if (pw) {
    pw.style.display = totalCount > 0 ? 'flex' : 'none';
    const fill = document.getElementById('followupProgressFill');
    if (fill) fill.style.width = completionPct + '%';
    const lbl = document.getElementById('followupProgressLabel');
    if (lbl) lbl.textContent = `${doneCount} of ${totalCount} completed (${completionPct}%)`;
  }

  // Apply filters
  let filtered = followups.filter(f => statusFilter === 'hidden' ? f.hidden : !f.hidden);
  if (statusFilter === 'pending') filtered = filtered.filter(f => f.richStatus === 'pending');
  else if (statusFilter === 'active') filtered = filtered.filter(f => f.richStatus === 'pending' || f.richStatus === 'in-progress');
  else if (statusFilter === 'blocked') filtered = filtered.filter(f => f.richStatus === 'blocked');
  else if (statusFilter === 'done') filtered = filtered.filter(f => f.done);

  if (sourceFilter !== 'all') filtered = filtered.filter(f => f.source === sourceFilter);
  if (priorityFilter !== 'all') filtered = filtered.filter(f => f.priority === priorityFilter);

  if (searchQ) {
    filtered = filtered.filter(f =>
      (f.text || '').toLowerCase().includes(searchQ) ||
      (f.school || '').toLowerCase().includes(searchQ) ||
      (f.teacher || '').toLowerCase().includes(searchQ) ||
      (f.owner || '').toLowerCase().includes(searchQ) ||
      (f.block || '').toLowerCase().includes(searchQ)
    );
  }

  // Sort
  const priOrder = { high: 0, medium: 1, low: 2 };
  if (sortBy === 'date-asc') filtered.sort((a, b) => (dateOnlyToMs(a.sourceDate) || 0) - (dateOnlyToMs(b.sourceDate) || 0));
  else if (sortBy === 'priority') filtered.sort((a, b) => (priOrder[a.priority] ?? 1) - (priOrder[b.priority] ?? 1));
  else if (sortBy === 'sla') filtered.sort((a, b) => {
    const da = a.dueInDays !== null ? a.dueInDays : 9999;
    const db2 = b.dueInDays !== null ? b.dueInDays : 9999;
    return da - db2;
  });
  else if (sortBy === 'school') filtered.sort((a, b) => (a.school || '').localeCompare(b.school || ''));
  else filtered.sort((a, b) => (dateOnlyToMs(b.sourceDate) || 0) - (dateOnlyToMs(a.sourceDate) || 0));
  // Pinned always first
  filtered.sort((a, b) => (b.pinned ? 1 : 0) - (a.pinned ? 1 : 0));

  const container = document.getElementById('followupsContainer');

  if (filtered.length === 0) {
    const msgs = { pending: 'No pending follow-ups — great work!', done: 'No completed follow-ups yet', blocked: 'No blocked follow-ups' };
    const msg = msgs[statusFilter] || (searchQ ? 'No follow-ups match your search' : 'No follow-ups match the selected filters');
    container.innerHTML = `<div class="empty-state"><i class="fas fa-tasks"></i><h3>${msg}</h3><p>Follow-ups are collected from visit notes, observation suggestions, meeting actions, and manual entries.</p></div>`;
    return;
  }

  if (_followupView === 'kanban') {
    container.innerHTML = _renderFollowupKanban(filtered);
    return;
  }

  // List view with optional grouping
  if (groupBy !== 'none') {
    const groups = new Map();
    filtered.forEach(f => {
      let key = groupBy === 'school' ? (f.school || 'Unknown School') :
        groupBy === 'source' ? (ACTION_CLOSURE_SOURCE_LABELS[f.source] || f.source || 'Other') :
          groupBy === 'priority' ? (f.priority || 'medium') :
            (f.block || 'Unknown Block');
      if (!groups.has(key)) groups.set(key, []);
      groups.get(key).push(f);
    });
    const sorted = [...groups.entries()].sort((a, b) =>
      groupBy === 'priority' ? ((priOrder[a[0]] ?? 1) - (priOrder[b[0]] ?? 1)) : a[0].localeCompare(b[0])
    );
    const priColors = { high: '#ef4444', medium: '#f59e0b', low: '#10b981' };
    let html = '';
    sorted.forEach(([key, items]) => {
      const dot = groupBy === 'priority' ? `<span class="fu-group-dot" style="background:${priColors[key] || '#94a3b8'}"></span>` : '<i class="fas fa-layer-group" style="color:var(--accent);font-size:12px"></i>';
      html += `<div class="fu-group-header">${dot} <span>${escapeHtml(key.charAt(0).toUpperCase() + key.slice(1))}</span> <span class="fu-group-count">${items.length}</span></div>`;
      html += items.map(f => _renderFollowupCard(f)).join('');
    });
    container.innerHTML = html;
    return;
  }

  const pg = getPaginatedItems(filtered, 'followups', getPageSize(20));
  container.innerHTML = pg.items.map(f => _renderFollowupCard(f)).join('') + renderPaginationControls('followups', pg, 'renderFollowups');
}

function _renderFollowupCard(f) {
  const priColors = { high: '#ef4444', medium: '#f59e0b', low: '#10b981' };
  const priLabels = { high: 'High', medium: 'Medium', low: 'Low' };
  const priIcons = { high: 'fa-fire', medium: 'fa-circle-half-stroke', low: 'fa-leaf' };
  const statusColors = { pending: '#94a3b8', 'in-progress': '#3b82f6', blocked: '#ef4444', done: '#10b981' };
  const statusLabels = { pending: 'Pending', 'in-progress': 'In Progress', blocked: 'Blocked', done: 'Done' };
  const statusIcons = { pending: 'fa-hourglass-half', 'in-progress': 'fa-spinner', blocked: 'fa-ban', done: 'fa-check-circle' };
  const richStatus = f.richStatus || (f.done ? 'done' : 'pending');
  const priColor = priColors[f.priority] || '#94a3b8';
  const statusColor = statusColors[richStatus] || '#94a3b8';
  const sourceMs = dateOnlyToMs(f.sourceDate || f.date);
  const dateStr = sourceMs !== null ? new Date(sourceMs).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' }) : 'No date';
  const sourceLabel = ACTION_CLOSURE_SOURCE_LABELS[f.source] || (f.source === 'manual' ? 'Manual' : 'Action');
  const sourceCls = f.source === 'visit' ? 'followup-visit' : f.source === 'observation' ? 'followup-obs' : f.source === 'manual' ? 'followup-manual' : 'followup-meeting';
  const dueText = f.dueDate ? new Date(f.dueDate + 'T00:00:00').toLocaleDateString('en-IN', { day: 'numeric', month: 'short' }) : 'No SLA';
  const dueClass = f.isOverdue ? 'overdue' : (f.dueInDays !== null && f.dueInDays <= 2 && !f.done ? 'soon' : '');
  const slaText = f.dueInDays === null ? 'No SLA' : f.dueInDays < 0 ? `Overdue ${Math.abs(f.dueInDays)}d` : f.dueInDays === 0 ? 'Due today' : `Due in ${f.dueInDays}d`;
  const suggestHigh = !f.done && f.detectedPriority === 'high' && f.priority !== 'high';
  const isManual = f.source === 'manual';

  const notesHtml = (f.notes || []).map(n => `
 <div class="fu-note-item">
 <span class="fu-note-text">${escapeHtml(n.text)}</span>
 <span class="fu-note-time">${escapeHtml(formatFollowupHistoryTime(n.ts))}</span>
 <button class="fu-note-del" onclick="deleteFollowupNote('${f.id}','${n.id}')" title="Delete note">&times;</button>
 </div>`).join('');

  const historyEvents = (f.history || []).slice().sort((a, b) => new Date(b.ts || 0) - new Date(a.ts || 0)).slice(0, 6);
  const historyHtml = historyEvents.length > 0
    ? historyEvents.map(h => `<div class="followup-history-item"><span class="followup-history-time">${escapeHtml(formatFollowupHistoryTime(h.ts) || '')}</span><span class="followup-history-text">${escapeHtml(h.message || h.type || '')}</span></div>`).join('')
    : '<div class="followup-history-empty">No events yet.</div>';

  return `<div class="followup-item fu-rich ${f.done ? 'done' : ''} ${f.urgency} ${f.pinned ? 'fu-pinned' : ''}" style="border-left:3px solid ${priColor}">
 ${f.pinned ? `<div class="fu-pin-badge" title="Pinned"><i class="fas fa-thumbtack"></i></div>` : ''}
 <div class="followup-check" onclick="setFollowupRichStatus('${f.id}','${f.done ? 'pending' : 'done'}')" title="${f.done ? 'Re-open' : 'Mark complete'}">
 ${f.done ? '<i class="fas fa-check-circle" style="color:var(--success)"></i>' : '<i class="far fa-circle"></i>'}
 </div>
 <div class="followup-body">
 <div class="followup-header">
 <span class="followup-source ${sourceCls}"><i class="fas ${f.icon || 'fa-tasks'}"></i> ${sourceLabel}</span>
 <span class="followup-school">${escapeHtml(f.school || 'Unknown School')}</span>
 ${f.teacher ? `<span class="followup-teacher"><i class="fas fa-user"></i> ${escapeHtml(f.teacher)}</span>` : ''}
 ${f.block ? `<span class="fu-meta-chip"><i class="fas fa-map-marker-alt"></i> ${escapeHtml(f.block)}</span>` : ''}
 <div class="fu-badges">
 <span class="fu-priority-badge" style="background:${priColor}20;color:${priColor};border:1px solid ${priColor}40"><i class="fas ${priIcons[f.priority] || 'fa-circle'}"></i> ${priLabels[f.priority] || 'Medium'}</span>
 <span class="fu-status-badge" style="background:${statusColor}20;color:${statusColor};border:1px solid ${statusColor}40"><i class="fas ${statusIcons[richStatus] || 'fa-circle'}"></i> ${statusLabels[richStatus] || richStatus}</span>
 ${suggestHigh ? `<span class="fu-ai-suggest" title="AI detected high-priority keywords in this text"><i class="fas fa-bolt"></i> Suggest: High Priority</span>` : ''}
 </div>
 </div>
 <p class="followup-text">${escapeHtml(f.text)}</p>
 <div class="followup-footer">
 <span class="followup-date"><i class="fas fa-calendar"></i> ${dateStr}</span>
 ${!f.done && f.daysSinceSource > 0 ? `<span class="followup-age ${f.urgency}">${f.daysSinceSource}d ago</span>` : ''}
 <span class="followup-owner" onclick="setFollowupOwner('${f.id}')" title="Click to reassign" style="cursor:pointer"><i class="fas fa-user-tag"></i> ${escapeHtml(f.owner)}</span>
 <span class="followup-sla ${dueClass}" onclick="setFollowupDueDate('${f.id}')" title="Click to set SLA" style="cursor:pointer"><i class="fas fa-hourglass-half"></i> ${slaText} · ${dueText}</span>
 ${f.done && f.closureLabel ? `<span class="followup-closure ${f.closureMode === 'auto' ? 'auto' : ''}"><i class="fas fa-link"></i> ${escapeHtml(f.closureLabel)}</span>` : ''}
 </div>
 ${f.notes && f.notes.length > 0 ? `<div class="fu-notes-section"><div class="fu-notes-title"><i class="fas fa-sticky-note"></i> Notes (${f.notes.length})</div><div class="fu-notes-list">${notesHtml}</div></div>` : ''}
 <div class="followup-actions-row">
 <select class="fu-status-select" onchange="setFollowupRichStatus('${f.id}',this.value)" title="Change status">
 <option value="pending" ${richStatus === 'pending' ? 'selected' : ''}>Pending</option>
 <option value="in-progress" ${richStatus === 'in-progress' ? 'selected' : ''}>In Progress</option>
 <option value="blocked" ${richStatus === 'blocked' ? 'selected' : ''}>Blocked</option>
 <option value="done" ${richStatus === 'done' ? 'selected' : ''}>Done</option>
 </select>
 <select class="fu-priority-select" onchange="setFollowupPriority('${f.id}',this.value)" title="Set priority">
 <option value="high" ${f.priority === 'high' ? 'selected' : ''}>High</option>
 <option value="medium" ${f.priority === 'medium' ? 'selected' : ''}>Medium</option>
 <option value="low" ${f.priority === 'low' ? 'selected' : ''}>Low</option>
 </select>
 <button class="btn btn-ghost btn-sm" onclick="setFollowupOwner('${f.id}')"><i class="fas fa-user-pen"></i> Assign</button>
 <button class="btn btn-ghost btn-sm" onclick="setFollowupDueDate('${f.id}')"><i class="fas fa-calendar-day"></i> SLA</button>
 <button class="btn btn-ghost btn-sm" onclick="addFollowupNotePrompt('${f.id}')"><i class="fas fa-sticky-note"></i> Note</button>
 <button class="btn btn-ghost btn-sm" onclick="linkFollowupEvidence('${f.id}')"><i class="fas fa-link"></i> Link</button>
 <button class="btn btn-ghost btn-sm" onclick="toggleFollowupPin('${f.id}')" title="${f.pinned ? 'Unpin' : 'Pin to top'}"><i class="fas fa-thumbtack" ${f.pinned ? 'style="color:var(--warning)"' : ''}></i></button>
 ${isManual ? `<button class="btn btn-ghost btn-sm" onclick="editManualFollowup('${f.id}')"><i class="fas fa-edit"></i></button><button class="btn btn-ghost btn-sm" onclick="deleteManualFollowup('${f.id}')" style="color:var(--danger)"><i class="fas fa-trash"></i></button>` : f.hidden ? `<button class="btn btn-sm" style="background:var(--warning-light,#fef3c7);color:var(--warning,#d97706);border:1px solid var(--warning,#d97706)" onclick="unhideFollowup('${f.id}')" title="Restore this follow-up"><i class="fas fa-eye"></i> Unhide</button>` : `<button class="btn btn-ghost btn-sm" onclick="hideFollowup('${f.id}')" title="Hide" style="color:var(--text-muted)"><i class="fas fa-eye-slash"></i></button>`}
 </div>
 <details class="fu-timeline-details">
 <summary class="followup-history-title"><i class="fas fa-clock-rotate-left"></i> Closure Timeline</summary>
 <div class="followup-history-list">${historyHtml}</div>
 </details>
 </div>
 </div>`;
}

function _renderFollowupKanban(followups) {
  const columns = [
    { key: 'pending', label: 'Pending', icon: 'fa-hourglass-half', color: '#94a3b8' },
    { key: 'in-progress', label: 'In Progress', icon: 'fa-spinner', color: '#3b82f6' },
    { key: 'blocked', label: 'Blocked', icon: 'fa-ban', color: '#ef4444' },
    { key: 'done', label: 'Completed', icon: 'fa-check-circle', color: '#10b981' }
  ];
  const priColors = { high: '#ef4444', medium: '#f59e0b', low: '#10b981' };
  return `<div class="fu-kanban-board">
 ${columns.map(col => {
    const items = followups.filter(f => (f.richStatus || (f.done ? 'done' : 'pending')) === col.key);
    return `<div class="fu-kanban-col">
 <div class="fu-kanban-col-header" style="border-top:3px solid ${col.color}">
 <i class="fas ${col.icon}" style="color:${col.color}"></i>
 <span>${col.label}</span>
 <span class="fu-kanban-count" style="background:${col.color}20;color:${col.color}">${items.length}</span>
 </div>
 <div class="fu-kanban-cards">
 ${items.length === 0 ? `<div class="fu-kanban-empty">No items</div>` : items.map(f => {
      const pc = priColors[f.priority] || '#94a3b8';
      const srcMs = dateOnlyToMs(f.sourceDate);
      const ds = srcMs ? new Date(srcMs).toLocaleDateString('en-IN', { day: 'numeric', month: 'short' }) : '';
      const txt = (f.text || '').length > 90 ? (f.text || '').substring(0, 90) + '...' : (f.text || '');
      return `<div class="fu-kanban-card ${f.pinned ? 'fu-pinned' : ''}" style="border-left:3px solid ${pc}">
 ${f.pinned ? '<span class="fu-pin-badge-sm"><i class="fas fa-thumbtack"></i></span>' : ''}
 <div class="fu-kc-school">${escapeHtml(f.school || 'Unknown')}</div>
 <div class="fu-kc-text">${escapeHtml(txt)}</div>
 <div class="fu-kc-meta">
 <span style="color:${pc};font-size:10px;font-weight:700">${(f.priority || 'medium').toUpperCase()}</span>
 ${ds ? `<span style="font-size:10px;color:var(--text-muted)">${ds}</span>` : ''}
 ${f.isOverdue ? `<span style="color:#ef4444;font-size:10px;font-weight:700">⚠ Overdue ${Math.abs(f.dueInDays || 0)}d</span>` : (f.dueInDays !== null && f.dueInDays <= 3 && !f.done ? `<span style="color:#f59e0b;font-size:10px">Due ${f.dueInDays}d</span>` : '')}
 </div>
 <select class="fu-status-select" onchange="setFollowupRichStatus('${f.id}',this.value)">
 <option value="pending" ${col.key === 'pending' ? 'selected' : ''}>Pending</option>
 <option value="in-progress" ${col.key === 'in-progress' ? 'selected' : ''}>In Progress</option>
 <option value="blocked" ${col.key === 'blocked' ? 'selected' : ''}>Blocked</option>
 <option value="done" ${col.key === 'done' ? 'selected' : ''}>Done</option>
 </select>
 </div>`;
    }).join('')}
 </div>
 </div>`;
  }).join('')}
 </div>`;
}

function toggleFollowup(id) {
  const followupStatus = DB.get('followupStatus') || [];
  let existing = followupStatus.find(f => f.id === id);
  if (!existing) {
    const item = collectFollowupItems().find(f => f.id === id);
    if (!item) return;
    existing = upsertFollowupLifecycle(followupStatus, item).entry;
  }

  existing.done = !existing.done;
  existing.status = existing.done ? 'done' : 'pending';
  existing.updatedAt = new Date().toISOString();

  if (existing.done) {
    if (!existing.closedAt) existing.closedAt = new Date().toISOString();
    if (!existing.closureLabel) existing.closureLabel = 'Closed manually';
    if (!existing.closureType) existing.closureType = 'manual';
    if (!existing.closureMode) existing.closureMode = 'manual';
    if (!existing.closureDate) existing.closureDate = normalizeDateOnly(new Date());
    addFollowupHistory(existing, 'closed', `Action marked completed (${existing.closureLabel || 'manual closure'})`);
  } else {
    existing.reopenedAt = new Date().toISOString();
    addFollowupHistory(existing, 'reopened', 'Action reopened and marked pending');
  }

  DB.set('followupStatus', followupStatus);
  renderFollowups();
  showToast(existing.done ? 'Follow-up completed' : 'Follow-up marked as pending');
}
// ===== IDEA TRACKER =====
let currentIdeaView = 'board';

function setIdeaView(view) {
  currentIdeaView = view;
  _pageState.ideas = 1;
  document.querySelectorAll('.idea-view-toggle .view-btn').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.view === view);
  });
  renderIdeas();
}

function openIdeaModal(id) {
  const form = document.getElementById('ideaForm');
  form.reset();
  document.getElementById('ideaId').value = '';
  document.getElementById('ideaModalTitle').innerHTML = '<i class="fas fa-lightbulb"></i> New Idea';

  // Reset color picker
  document.querySelectorAll('#ideaColorPicker .color-dot').forEach((dot, i) => {
    dot.classList.toggle('active', i === 0);
  });

  if (id) {
    const ideas = DB.get('ideas');
    const idea = ideas.find(i => i.id === id);
    if (idea) {
      document.getElementById('ideaModalTitle').innerHTML = '<i class="fas fa-lightbulb"></i> Edit Idea';
      document.getElementById('ideaId').value = idea.id;
      document.getElementById('ideaTitle').value = idea.title;
      document.getElementById('ideaCategory').value = idea.category || 'Other';
      document.getElementById('ideaStatus').value = idea.status || 'spark';
      document.getElementById('ideaPriority').value = idea.priority || 'medium';
      document.getElementById('ideaDescription').value = idea.description || '';
      document.getElementById('ideaTags').value = (idea.tags || []).join(', ');
      document.getElementById('ideaInspiration').value = idea.inspiration || '';

      // Set color
      const color = idea.color || '#f59e0b';
      document.querySelectorAll('#ideaColorPicker .color-dot').forEach(dot => {
        dot.classList.toggle('active', dot.dataset.color === color);
      });
    }
  }

  document.getElementById('ideaModal').classList.add('active');
}

function pickIdeaColor(el) {
  document.querySelectorAll('#ideaColorPicker .color-dot').forEach(d => d.classList.remove('active'));
  el.classList.add('active');
}

function saveIdea(e) {
  e.preventDefault();
  const ideas = DB.get('ideas');
  const id = document.getElementById('ideaId').value;
  const activeColor = document.querySelector('#ideaColorPicker .color-dot.active');
  const tagsRaw = document.getElementById('ideaTags').value;
  const tags = tagsRaw ? tagsRaw.split(',').map(t => t.trim()).filter(Boolean) : [];

  const idea = {
    id: id || DB.generateId(),
    title: document.getElementById('ideaTitle').value.trim(),
    category: document.getElementById('ideaCategory').value,
    status: document.getElementById('ideaStatus').value,
    priority: document.getElementById('ideaPriority').value,
    description: document.getElementById('ideaDescription').value.trim(),
    tags: tags,
    inspiration: document.getElementById('ideaInspiration').value.trim(),
    color: activeColor ? activeColor.dataset.color : '#f59e0b',
    createdAt: id ? (ideas.find(i => i.id === id) || {}).createdAt || new Date().toISOString() : new Date().toISOString(),
    updatedAt: new Date().toISOString()
  };

  if (id) {
    const idx = ideas.findIndex(i => i.id === id);
    if (idx !== -1) ideas[idx] = idea;
  } else {
    ideas.push(idea);
  }

  DB.set('ideas', ideas);
  closeModal('ideaModal');
  renderIdeas();
  showToast(id ? 'Idea updated!' : 'New idea captured! ');
}

async function deleteIdea(id) {
  if (!await confirmAction('Delete this idea?')) return;
  let ideas = DB.get('ideas');
  ideas = ideas.filter(i => i.id !== id);
  DB.set('ideas', ideas);
  renderIdeas();
  showToast('Idea deleted');
}

function moveIdeaStatus(id, newStatus) {
  const ideas = DB.get('ideas');
  const idea = ideas.find(i => i.id === id);
  if (idea) {
    idea.status = newStatus;
    idea.updatedAt = new Date().toISOString();
    DB.set('ideas', ideas);
    renderIdeas();
  }
}

function renderIdeaStats() {
  const ideas = DB.get('ideas');
  const statuses = { spark: 0, exploring: 0, 'in-progress': 0, done: 0, archived: 0 };
  ideas.forEach(i => { if (statuses.hasOwnProperty(i.status)) statuses[i.status]++; });

  const statsConfig = [
    { emoji: '<i class="fas fa-lightbulb"></i>', label: 'Sparks', value: statuses.spark, color: '#f59e0b' },
    { emoji: '<i class="fas fa-search"></i>', label: 'Exploring', value: statuses.exploring, color: '#3b82f6' },
    { emoji: '<i class="fas fa-rocket"></i>', label: 'In Progress', value: statuses['in-progress'], color: '#8b5cf6' },
    { emoji: '<i class="fas fa-check-circle"></i>', label: 'Done', value: statuses.done, color: '#10b981' },
    { emoji: '<i class="fas fa-box-archive"></i>', label: 'Archived', value: statuses.archived, color: '#6b7280' },
    { emoji: '<i class="fas fa-layer-group"></i>', label: 'Total Ideas', value: ideas.length, color: '#ec4899' }
  ];

  document.getElementById('ideaStats').innerHTML = statsConfig.map(s => `
 <div class="idea-stat-card" style="--stat-color: ${s.color}">
 <div class="stat-emoji">${s.emoji}</div>
 <div class="stat-value">${s.value}</div>
 <div class="stat-label">${s.label}</div>
 </div>
 `).join('');
}

function getFilteredIdeas() {
  let ideas = DB.get('ideas');
  const catFilter = document.getElementById('ideaCategoryFilter').value;
  const searchTerm = (document.getElementById('ideaSearchInput').value || '').toLowerCase();

  if (catFilter !== 'all') {
    ideas = ideas.filter(i => i.category === catFilter);
  }
  if (searchTerm) {
    ideas = ideas.filter(i =>
      (i.title || '').toLowerCase().includes(searchTerm) ||
      (i.description || '').toLowerCase().includes(searchTerm) ||
      (i.tags || []).some(t => t.toLowerCase().includes(searchTerm)) ||
      (i.inspiration || '').toLowerCase().includes(searchTerm) ||
      (i.category || '').toLowerCase().includes(searchTerm)
    );
  }
  return ideas;
}

function buildIdeaCard(idea) {
  const priorityLabels = { high: 'High', medium: 'Medium', low: 'Low' };
  const categoryEmojis = {
    Teaching: '<i class="fas fa-chalkboard-teacher"></i>',
    Activity: '<i class="fas fa-palette"></i>',
    Training: '<i class="fas fa-clipboard-list"></i>',
    Resource: '<i class="fas fa-book"></i>',
    Community: '<i class="fas fa-users"></i>',
    Tech: '<i class="fas fa-laptop-code"></i>',
    Other: '<i class="fas fa-circle"></i>'
  };
  const d = new Date(idea.createdAt);
  const dateStr = d.toLocaleDateString('en-IN', { day: 'numeric', month: 'short' });

  const tagsHtml = (idea.tags || []).slice(0, 3).map(t => `<span class="idea-tag">${escapeHtml(t)}</span>`).join('');
  const descSnippet = idea.description ? `<div class="idea-card-desc">${escapeHtml(idea.description)}</div>` : '';

  // Status badge for grid/list views
  const statusLabels = { spark: 'Spark', exploring: 'Exploring', 'in-progress': 'In Progress', done: 'Done', archived: 'Archived' };

  return `
 <div class="idea-card" style="--card-accent: ${idea.color || '#f59e0b'}" onclick="openIdeaModal('${idea.id}')">
 <div class="idea-card-header">
 <div class="idea-card-title">${escapeHtml(idea.title)}</div>
 <span class="idea-card-priority ${idea.priority}">${priorityLabels[idea.priority] || 'Medium'}</span>
 </div>
 ${descSnippet}
 ${tagsHtml ? `<div class="idea-card-tags">${tagsHtml}</div>` : ''}
 <div class="idea-card-footer">
 <div class="idea-card-category">${categoryEmojis[idea.category] || '<i class="fas fa-circle"></i>'} ${escapeHtml(idea.category || 'Other')}</div>
 <span class="idea-status-badge ${idea.status}">${statusLabels[idea.status] || escapeHtml(idea.status)}</span>
 <span class="idea-card-date">${dateStr}</span>
 <div class="idea-card-actions" onclick="event.stopPropagation()">
 <button onclick="openIdeaModal('${idea.id}')" title="Edit"><i class="fas fa-pen"></i></button>
 ${idea.status === 'archived'
      ? `<button onclick="unarchiveIdea('${idea.id}')" title="Unarchive" class="unarchive-btn"><i class="fas fa-box-open"></i></button>`
      : `<button onclick="archiveIdea('${idea.id}')" title="Archive" class="archive-btn"><i class="fas fa-archive"></i></button>`
    }
 <button class="delete-btn" onclick="deleteIdea('${idea.id}')" title="Delete"><i class="fas fa-trash"></i></button>
 </div>
 </div>
 </div>
 `;
}

function archiveIdea(id) {
  const ideas = DB.get('ideas');
  const idea = ideas.find(i => i.id === id);
  if (idea) {
    idea.status = 'archived';
    idea.updatedAt = new Date().toISOString();
    DB.set('ideas', ideas);
    renderIdeas();
    showToast('Idea archived ');
  }
}

function unarchiveIdea(id) {
  const ideas = DB.get('ideas');
  const idea = ideas.find(i => i.id === id);
  if (idea) {
    idea.status = 'spark';
    idea.updatedAt = new Date().toISOString();
    DB.set('ideas', ideas);
    renderIdeas();
    showToast('Idea unarchived moved back to Spark ');
  }
}

function renderIdeas() {
  renderIdeaStats();
  const ideas = getFilteredIdeas();
  const container = document.getElementById('ideasContainer');

  if (ideas.length === 0) {
    container.innerHTML = `
 <div class="idea-empty">
 <i class="fas fa-lightbulb"></i>
 <h3>No ideas yet</h3>
 <p>Click <strong>"New Idea"</strong> to capture your first spark </p>
 </div>
 `;
    return;
  }

  if (currentIdeaView === 'board') {
    renderIdeaBoard(ideas, container);
  } else if (currentIdeaView === 'grid') {
    renderIdeaGrid(ideas, container);
  } else {
    renderIdeaList(ideas, container);
  }
}

function renderIdeaBoard(ideas, container) {
  const columns = [
    { key: 'spark', title: 'Spark', color: '#f59e0b' },
    { key: 'exploring', title: 'Exploring', color: '#3b82f6' },
    { key: 'in-progress', title: 'In Progress', color: '#8b5cf6' },
    { key: 'done', title: 'Done', color: '#10b981' },
    { key: 'archived', title: 'Archived', color: '#6b7280' }
  ];

  const sortedByPriority = (arr) => {
    const order = { high: 0, medium: 1, low: 2 };
    return arr.sort((a, b) => (order[a.priority] || 1) - (order[b.priority] || 1));
  };

  container.innerHTML = `<div class="idea-board">
 ${columns.map(col => {
    const colIdeas = sortedByPriority(ideas.filter(i => i.status === col.key));
    return `
 <div class="idea-board-column">
 <div class="idea-column-header">
 <span class="col-title" style="color: ${col.color}">${col.title}</span>
 <span class="col-count">${colIdeas.length}</span>
 </div>
 <div class="idea-column-body">
 ${colIdeas.length ? colIdeas.map(idea => buildIdeaCard(idea)).join('') : '<div style="text-align:center;color:var(--text-muted);font-size:13px;padding:20px 0;">No ideas here</div>'}
 </div>
 </div>
 `;
  }).join('')}
 </div>`;
}

function renderIdeaGrid(ideas, container) {
  const sorted = [...ideas].sort((a, b) => new Date(b.updatedAt || b.createdAt) - new Date(a.updatedAt || a.createdAt));
  const pg = getPaginatedItems(sorted, 'ideas', getPageSize(18));
  container.innerHTML = `<div class="idea-grid">${pg.items.map(idea => buildIdeaCard(idea)).join('')}</div>` + renderPaginationControls('ideas', pg, 'renderIdeas');
}

function renderIdeaList(ideas, container) {
  const sorted = [...ideas].sort((a, b) => new Date(b.updatedAt || b.createdAt) - new Date(a.updatedAt || a.createdAt));
  const pg = getPaginatedItems(sorted, 'ideas', getPageSize(20));
  const statusLabels = { spark: 'Spark', exploring: 'Exploring', 'in-progress': 'In Progress', done: 'Done', archived: 'Archived' };
  container.innerHTML = `<div class="idea-list">${pg.items.map(idea => `
 <div class="idea-card" style="--card-accent: ${idea.color || '#f59e0b'}" onclick="openIdeaModal('${idea.id}')">
 <div style="flex:1;min-width:0;">
 <div class="idea-card-header">
 <div class="idea-card-title">${escapeHtml(idea.title)}</div>
 </div>
 </div>
 <span class="idea-status-badge ${idea.status}">${statusLabels[idea.status] || escapeHtml(idea.status)}</span>
 <span class="idea-card-priority ${idea.priority}">${escapeHtml(idea.priority)}</span>
 <span class="idea-card-category">${escapeHtml(idea.category || 'Other')}</span>
 <span class="idea-card-date">${new Date(idea.createdAt).toLocaleDateString('en-IN', { day: 'numeric', month: 'short' })}</span>
 <div class="idea-card-actions" onclick="event.stopPropagation()" style="opacity:1;">
 <button onclick="openIdeaModal('${idea.id}')" title="Edit"><i class="fas fa-pen"></i></button>
 ${idea.status === 'archived'
      ? `<button onclick="unarchiveIdea('${idea.id}')" title="Unarchive" class="unarchive-btn"><i class="fas fa-box-open"></i></button>`
      : `<button onclick="archiveIdea('${idea.id}')" title="Archive" class="archive-btn"><i class="fas fa-archive"></i></button>`
    }
 <button class="delete-btn" onclick="deleteIdea('${idea.id}')" title="Delete"><i class="fas fa-trash"></i></button>
 </div>
 </div>
 `).join('')}</div>` + renderPaginationControls('ideas', pg, 'renderIdeas');
}

// ===== SCHOOL PROFILE IMPORT FROM EXCEL =====
let _schoolImportRows = [];
let _schoolImportFileName = '';

function triggerSchoolProfileImport() {
  document.getElementById('obsImportMenu')?.classList.remove('show');
  document.getElementById('schoolProfileImportFile').click();
}

async function loadSchoolProfileImportPreview(event) {
  const file = event.target.files[0];
  if (!file) return;
  event.target.value = '';

  _schoolImportFileName = file.name;
  _schoolImportRows = [];

  document.getElementById('schoolImportLoading').style.display = 'flex';
  document.getElementById('schoolImportContent').style.display = 'none';
  document.getElementById('schoolImportConfirmBtn').disabled = true;
  document.getElementById('schoolProfileImportModal').classList.add('active');

  try {
    const data = await file.arrayBuffer();
    const wb = XLSX.read(data, { type: 'array' });

    let rows = [];
    for (const sheetName of wb.SheetNames) {
      const ws = wb.Sheets[sheetName];
      const sheetRows = XLSX.utils.sheet_to_json(ws, { raw: false, dateNF: 'dd-mm-yyyy' });
      if (sheetRows.length > 0) rows = rows.concat(sheetRows);
    }

    if (rows.length === 0) {
      showToast('No data found in Excel file', 'error');
      closeModal('schoolProfileImportModal');
      return;
    }

    // Check if it's a DMT file
    const cols = Object.keys(rows[0]);
    const isDMT = cols.some(c => c.includes('School Name') || c.includes('Teacher: Teacher Name') || c.includes('Practice Type'));
    if (!isDMT) {
      showToast('This does not appear to be a DMT Field Notes Excel. Needs "School Name" column.', 'error', 6000);
      closeModal('schoolProfileImportModal');
      return;
    }

    _schoolImportRows = rows;

    // Extract unique values for filters
    const states = [...new Set(rows.map(r => (r['State'] || '').trim()).filter(Boolean))].sort();
    const blocks = [...new Set(rows.map(r => (r['Block Name'] || '').trim()).filter(Boolean))].sort();
    const clusters = [...new Set(rows.map(r => (r['Cluster'] || '').trim()).filter(Boolean))].sort();
    const observers = [...new Set(rows.map(r => (r['Actual Observer: Full Name'] || r['Primary Observer: Full Name'] || '').trim()).filter(Boolean))].sort();

    const populateSelect = (id, label, values) => {
      const el = document.getElementById(id);
      if (!el) return;
      el.innerHTML = `<option value="all">All ${label} (${values.length})</option>` +
        values.map(v => `<option value="${escapeHtml(v)}">${escapeHtml(v)}</option>`).join('');
    };

    populateSelect('schoolImportFilterState', 'States', states);
    populateSelect('schoolImportFilterBlock', 'Blocks', blocks);
    populateClusterCheckboxes('schoolImportClusterList', clusters, 'previewSchoolProfileImport()');
    updateClusterCount('schoolImportFilterCluster', 'schoolImportClusterCount');
    populateSelect('schoolImportFilterObserver', 'Observers', observers);

    document.getElementById('schoolImportFileName').textContent = file.name;

    document.getElementById('schoolImportLoading').style.display = 'none';
    document.getElementById('schoolImportContent').style.display = 'block';
    previewSchoolProfileImport();
  } catch (err) {
    console.error('School profile import read error:', err);
    showToast('Failed to read Excel: ' + err.message, 'error');
    closeModal('schoolProfileImportModal');
  }
}

function getSchoolImportFilters() {
  return {
    state: document.getElementById('schoolImportFilterState')?.value || 'all',
    block: document.getElementById('schoolImportFilterBlock')?.value || 'all',
    clusters: getSelectedClusters('schoolImportClusterList'),
    observer: document.getElementById('schoolImportFilterObserver')?.value || 'all'
  };
}

function getFilteredSchoolImportRows() {
  const f = getSchoolImportFilters();
  const anyFilter = f.state !== 'all' || f.block !== 'all' || f.clusters !== null || f.observer !== 'all';
  if (!anyFilter) return { rows: _schoolImportRows, anyFilter: false };

  const filtered = _schoolImportRows.filter(row => {
    const rowState = (row['State'] || '').trim();
    const rowBlock = (row['Block Name'] || '').trim();
    const rowCluster = (row['Cluster'] || '').trim();
    const rowObserver = (row['Actual Observer: Full Name'] || row['Primary Observer: Full Name'] || '').trim();
    if (f.state !== 'all' && rowState !== f.state) return false;
    if (f.block !== 'all' && rowBlock !== f.block) return false;
    if (f.clusters !== null && !f.clusters.has(rowCluster)) return false;
    if (f.observer !== 'all' && rowObserver !== f.observer) return false;
    return true;
  });
  return { rows: filtered, anyFilter: true };
}

function extractSchoolProfilesFromRows(rows) {
  const schoolMap = {};
  rows.forEach(row => {
    const schoolName = (row['School Name'] || '').trim();
    if (!schoolName) return;
    const key = schoolName.toLowerCase();

    if (!schoolMap[key]) {
      schoolMap[key] = {
        name: schoolName,
        block: (row['Block Name'] || '').trim(),
        cluster: (row['Cluster'] || '').trim(),
        district: (row['District Name'] || '').trim(),
        state: (row['State'] || '').trim(),
        teachers: new Set(),
        subjects: new Set(),
        totalObservations: 0,
        dates: [],
        observers: new Set()
      };
    }

    const s = schoolMap[key];
    s.totalObservations++;
    const teacher = (row['Teacher: Teacher Name'] || '').trim();
    if (teacher) s.teachers.add(teacher);
    const subject = (row['Subject'] || '').trim();
    if (subject) s.subjects.add(subject);
    const observer = (row['Actual Observer: Full Name'] || row['Primary Observer: Full Name'] || '').trim();
    if (observer) s.observers.add(observer);
    if (!s.block && row['Block Name']) s.block = (row['Block Name'] || '').trim();
    if (!s.cluster && row['Cluster']) s.cluster = (row['Cluster'] || '').trim();
    if (!s.district && row['District Name']) s.district = (row['District Name'] || '').trim();
    if (!s.state && row['State']) s.state = (row['State'] || '').trim();

    const rawDate = row['Response Date'];
    if (rawDate instanceof Date) {
      s.dates.push(rawDate.toISOString().split('T')[0]);
    } else if (typeof rawDate === 'string' && rawDate) {
      const parsed = new Date(rawDate);
      if (!isNaN(parsed)) s.dates.push(parsed.toISOString().split('T')[0]);
    }
  });

  // Convert Sets to arrays and sort
  return Object.values(schoolMap).map(s => ({
    ...s,
    teachers: [...s.teachers],
    subjects: [...s.subjects],
    observers: [...s.observers],
    dates: s.dates.sort(),
    lastDate: s.dates.length > 0 ? s.dates.sort().pop() : '',
    firstDate: s.dates.length > 0 ? s.dates.sort()[0] : ''
  })).sort((a, b) => b.totalObservations - a.totalObservations);
}

function previewSchoolProfileImport() {
  const { rows, anyFilter } = getFilteredSchoolImportRows();
  const totalRows = _schoolImportRows.length;
  const schools = extractSchoolProfilesFromRows(rows);
  const allSchools = extractSchoolProfilesFromRows(_schoolImportRows);

  const previewEl = document.getElementById('schoolImportPreview');
  const countEl = document.getElementById('schoolImportCount');
  const listEl = document.getElementById('schoolImportSchoolList');
  const btn = document.getElementById('schoolImportConfirmBtn');
  const totalEl = document.getElementById('schoolImportTotalSchools');

  totalEl.textContent = allSchools.length;

  const blocks = [...new Set(schools.map(s => s.block).filter(Boolean))];
  const clusters = [...new Set(schools.map(s => s.cluster).filter(Boolean))];
  const totalTeachers = new Set(schools.flatMap(s => s.teachers)).size;

  const filterLabel = anyFilter
    ? `<strong>${schools.length}</strong> of ${allSchools.length} schools match your filters (from ${rows.length.toLocaleString()} rows)`
    : `All <strong>${allSchools.length}</strong> schools found (from ${totalRows.toLocaleString()} rows)`;

  // Check how many are already in visits
  const existingVisits = DB.get('visits');
  const existingSchoolKeys = new Set(existingVisits.map(v => (v.school || '').trim().toLowerCase()));
  const newSchools = schools.filter(s => !existingSchoolKeys.has(s.name.toLowerCase()));
  const existingCount = schools.length - newSchools.length;

  previewEl.innerHTML = `
 <div class="unload-preview-stats">
 <div class="unload-preview-count" style="color: var(--accent)">
 <i class="fas fa-${anyFilter ? 'filter' : 'database'}"></i>
 ${filterLabel}
 </div>
 <div class="unload-preview-details">
 <span><i class="fas fa-school"></i> ${schools.length} Schools</span>
 <span><i class="fas fa-plus-circle" style="color:#10b981;"></i> ${newSchools.length} New</span>
 <span><i class="fas fa-check-circle" style="color:#f59e0b;"></i> ${existingCount} Already Exist</span>
 <span><i class="fas fa-chalkboard-teacher"></i> ${totalTeachers} Teachers</span>
 <span><i class="fas fa-map-marker-alt"></i> ${blocks.length} Blocks</span>
 <span><i class="fas fa-layer-group"></i> ${clusters.length} Clusters</span>
 </div>
 </div>`;

  // Render school cards
  if (schools.length > 0) {
    listEl.innerHTML = `<div class="school-import-grid">${schools.slice(0, 50).map(s => {
      const isExisting = existingSchoolKeys.has(s.name.toLowerCase());
      return `<div class="school-import-card ${isExisting ? 'existing' : 'new-school'}">
 <div class="school-import-card-header">
 <span class="school-import-name">${escapeHtml(s.name)}</span>
 <span class="school-import-badge ${isExisting ? 'badge-existing' : 'badge-new'}">${isExisting ? 'Exists' : 'New'}</span>
 </div>
 <div class="school-import-meta">
 ${s.block ? `<span><i class="fas fa-map-marker-alt"></i> ${escapeHtml(s.block)}</span>` : ''}
 ${s.cluster ? `<span><i class="fas fa-layer-group"></i> ${escapeHtml(s.cluster)}</span>` : ''}
 ${s.district ? `<span><i class="fas fa-city"></i> ${escapeHtml(s.district)}</span>` : ''}
 </div>
 <div class="school-import-stats">
 <span><i class="fas fa-clipboard-list"></i> ${s.totalObservations} obs</span>
 <span><i class="fas fa-chalkboard-teacher"></i> ${s.teachers.length} teachers</span>
 ${s.lastDate ? `<span><i class="fas fa-calendar"></i> ${new Date(s.lastDate).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: '2-digit' })}</span>` : ''}
 </div>
 </div>`;
    }).join('')}</div>${schools.length > 50 ? `<p style="text-align:center;color:var(--text-muted);font-size:12px;margin-top:8px;">Showing 50 of ${schools.length} schools...</p>` : ''}`;
  } else {
    listEl.innerHTML = '<p style="text-align:center;color:var(--text-muted);padding:20px;">No schools found matching filters.</p>';
  }

  btn.disabled = schools.length === 0;
  countEl.textContent = schools.length;
}

async function executeSchoolProfileImport() {
  const { rows } = getFilteredSchoolImportRows();
  const schools = extractSchoolProfilesFromRows(rows);
  if (schools.length === 0) return;

  const f = getSchoolImportFilters();
  const filterDesc = [f.state !== 'all' ? `State: ${f.state}` : '', f.block !== 'all' ? `Block: ${f.block}` : '', f.clusters !== null ? `Clusters: ${[...f.clusters].join(', ')}` : '', f.observer !== 'all' ? `Observer: ${f.observer}` : ''].filter(Boolean).join(', ') || 'No filter';

  if (!await showPopupConfirm({ title: ' Import Schools', message: `Import <strong>${schools.length}</strong> school profiles from "${_schoolImportFileName}"?<br><small>Filter: ${filterDesc}</small><br><br>New schools get planned visits. Existing schools get updated info.`, icon: 'fa-school', confirmText: `Import ${schools.length} Schools`, confirmColor: '#10b981' })) return;

  let visits = DB.get('visits');
  const existingSchoolKeys = new Map();
  visits.forEach((v, i) => {
    const key = (v.school || '').trim().toLowerCase();
    if (!existingSchoolKeys.has(key)) existingSchoolKeys.set(key, i);
  });

  let newCount = 0;
  let updatedCount = 0;

  schools.forEach(s => {
    const key = s.name.toLowerCase();

    if (existingSchoolKeys.has(key)) {
      // Update existing visit with missing info
      const idx = existingSchoolKeys.get(key);
      let changed = false;
      if (!visits[idx].block && s.block) { visits[idx].block = s.block; changed = true; }
      if (!visits[idx].cluster && s.cluster) { visits[idx].cluster = s.cluster; changed = true; }
      if (!visits[idx].district && s.district) { visits[idx].district = s.district; changed = true; }
      if (!visits[idx].state && s.state) { visits[idx].state = s.state; changed = true; }
      if (changed) updatedCount++;
    } else {
      // Create a new planned visit for this school
      const visit = {
        id: DB.generateId(),
        school: s.name,
        block: s.block || '',
        cluster: s.cluster || '',
        district: s.district || '',
        state: s.state || '',
        date: new Date().toISOString().split('T')[0],
        status: 'planned',
        purpose: 'School Profile Import',
        notes: `Imported from Excel. ${s.teachers.length} teachers observed, ${s.totalObservations} observations. Subjects: ${s.subjects.join(', ') || 'N/A'}.${s.firstDate && s.lastDate ? ' Data range: ' + s.firstDate + ' to ' + s.lastDate : ''}`,
        followUp: '',
        createdAt: new Date().toISOString(),
        source: 'Excel Import'
      };
      visits.push(visit);
      existingSchoolKeys.set(key, visits.length - 1);
      newCount++;
    }
  });

  DB.set('visits', visits);
  closeModal('schoolProfileImportModal');
  _schoolImportRows = [];
  renderSchoolProfiles();

  const msg = [];
  if (newCount > 0) msg.push(`${newCount} new school profiles imported`);
  if (updatedCount > 0) msg.push(`${updatedCount} existing schools updated`);
  showToast(`${msg.join(', ')}! `, 'success', 5000);

  // Switch to schools section
  navigateTo('schools');
}

// ===== SCHOOL DELETE FUNCTIONS =====
async function deleteSchoolProfile(encodedKey) {
  const schoolKey = decodeURIComponent(encodedKey);
  const schoolMap = getSchoolData();
  const school = schoolMap[schoolKey];
  if (!school) { showToast('School not found', 'error'); return; }

  const visitCount = school.visits.length;
  const obsCount = school.observations.length;

  let msgParts = [`Delete school "<strong>${school.name}</strong>"?`];
  if (visitCount > 0 || obsCount > 0) {
    msgParts.push('<br><br>This will remove:');
    if (visitCount > 0) msgParts.push(`<br> ${visitCount} visit(s)`);
    if (obsCount > 0) msgParts.push(`<br> ${obsCount} observation(s)`);
    msgParts.push('<br><br><strong>This cannot be undone!</strong>');
  }

  if (!await showPopupConfirm({ title: ' Delete School', message: msgParts.join(''), icon: 'fa-school', confirmText: 'Delete School', confirmColor: '#ef4444' })) return;

  // Remove visits for this school
  if (visitCount > 0) {
    const visits = DB.get('visits');
    const filtered = visits.filter(v => (v.school || '').trim().toLowerCase() !== schoolKey);
    DB.set('visits', filtered);
  }

  // Remove observations for this school
  if (obsCount > 0) {
    const observations = DB.get('observations');
    const filtered = observations.filter(o => (o.school || '').trim().toLowerCase() !== schoolKey);
    DB.set('observations', filtered);
  }

  showToast(`School "${school.name}" deleted`, 'success');
  renderSchoolProfiles();
}

function openBulkDeleteSchools() {
  const schoolMap = getSchoolData();
  const schools = Object.values(schoolMap);
  if (schools.length === 0) {
    showToast('No schools to delete', 'info');
    return;
  }

  // Collect all visits to build filter data
  const visits = DB.get('visits');

  // Build per-school info for filtering
  const schoolInfos = schools.map(s => {
    const key = s.name.trim().toLowerCase();
    const schoolVisits = visits.filter(v => (v.school || '').trim().toLowerCase() === key);
    const sources = [...new Set(schoolVisits.map(v => v.source || 'Manual'))];
    const blocks = [...new Set([s.block, ...schoolVisits.map(v => v.block)].filter(Boolean))];
    const clusters = [...new Set(schoolVisits.map(v => v.cluster).filter(Boolean))];
    const statuses = [...new Set(schoolVisits.map(v => v.status).filter(Boolean))];
    return {
      name: s.name,
      key,
      visitCount: s.visits.length,
      obsCount: s.observations.length,
      block: blocks[0] || '',
      cluster: clusters[0] || '',
      sources,
      blocks,
      clusters,
      statuses
    };
  });

  // Populate filter checkboxes
  const allSources = [...new Set(schoolInfos.flatMap(s => s.sources))].sort();
  const allBlocks = [...new Set(schoolInfos.map(s => s.block).filter(Boolean))].sort();
  const allClusters = [...new Set(schoolInfos.flatMap(s => s.clusters))].sort();
  const allStatuses = [...new Set(schoolInfos.flatMap(s => s.statuses))].sort();

  _schoolDelInfos = schoolInfos;

  populateSchoolDelCheckboxes('schoolDelSourceList', allSources);
  populateSchoolDelCheckboxes('schoolDelBlockList', allBlocks);
  populateSchoolDelCheckboxes('schoolDelClusterList', allClusters);
  populateSchoolDelCheckboxes('schoolDelStatusList', allStatuses);

  previewBulkDeleteSchools();
  openModal('bulkDeleteSchoolsModal');
}

let _schoolDelInfos = [];

function populateSchoolDelCheckboxes(containerId, values) {
  const container = document.getElementById(containerId);
  if (!container) return;
  if (values.length === 0) {
    container.innerHTML = '<span style="color:var(--text-muted);font-size:11px;padding:4px;">None available</span>';
    return;
  }
  container.innerHTML = values.map(v =>
    `<label class="bulk-checkbox"><input type="checkbox" checked onchange="previewBulkDeleteSchools()" value="${escapeHtml(v)}"> ${escapeHtml(v || 'N/A')}</label>`
  ).join('');
}

function schoolDelFilterToggle(filter, mode) {
  const idMap = { source: 'schoolDelSourceList', block: 'schoolDelBlockList', cluster: 'schoolDelClusterList', status: 'schoolDelStatusList' };
  const container = document.getElementById(idMap[filter]);
  if (!container) return;
  const checkboxes = container.querySelectorAll('input[type="checkbox"]');
  checkboxes.forEach(cb => cb.checked = mode === 'all');
  previewBulkDeleteSchools();
}

function getSchoolDelChecked(containerId) {
  const container = document.getElementById(containerId);
  if (!container) return new Set();
  return new Set([...container.querySelectorAll('input[type="checkbox"]:checked')].map(cb => cb.value));
}

function getBulkDeleteSchoolsFiltered() {
  const sources = getSchoolDelChecked('schoolDelSourceList');
  const blocks = getSchoolDelChecked('schoolDelBlockList');
  const clusters = getSchoolDelChecked('schoolDelClusterList');
  const statuses = getSchoolDelChecked('schoolDelStatusList');

  return _schoolDelInfos.filter(s => {
    const matchesSource = s.sources.some(src => sources.has(src));
    const matchesBlock = !s.block || blocks.has(s.block);
    const matchesCluster = s.clusters.length === 0 || s.clusters.some(c => clusters.has(c));
    const matchesStatus = s.statuses.length === 0 || s.statuses.some(st => statuses.has(st));
    return matchesSource && matchesBlock && matchesCluster && matchesStatus;
  });
}

function previewBulkDeleteSchools() {
  const filtered = getBulkDeleteSchoolsFiltered();
  const total = _schoolDelInfos.length;
  const totalVisits = filtered.reduce((s, x) => s + x.visitCount, 0);
  const totalObs = filtered.reduce((s, x) => s + x.obsCount, 0);

  const previewEl = document.getElementById('schoolDelPreview');
  const countEl = document.getElementById('schoolDelCount');
  const btn = document.getElementById('schoolDelConfirmBtn');

  previewEl.innerHTML = `
 <div style="display:flex;align-items:center;gap:12px;flex-wrap:wrap;padding:10px 14px;background:${filtered.length > 0 ? 'rgba(239,68,68,0.08)' : 'var(--bg-secondary)'};border-radius:10px;border:1px solid ${filtered.length > 0 ? 'rgba(239,68,68,0.2)' : 'var(--border)'};">
 <span style="font-size:13px;color:${filtered.length > 0 ? '#ef4444' : 'var(--text-muted)'};">
 <i class="fas fa-${filtered.length > 0 ? 'exclamation-triangle' : 'info-circle'}"></i>
 <strong>${filtered.length}</strong> of ${total} schools will be deleted
 </span>
 <span style="font-size:11px;color:var(--text-muted);"><i class="fas fa-school"></i> ${totalVisits} visits</span>
 <span style="font-size:11px;color:var(--text-muted);"><i class="fas fa-clipboard-list"></i> ${totalObs} observations</span>
 </div>
 `;

  // Show school list preview
  const listEl = document.getElementById('schoolDelList');
  if (filtered.length > 0) {
    listEl.innerHTML = filtered.slice(0, 40).map(s => `
 <div class="school-del-item">
 <div class="school-del-name"><i class="fas fa-school"></i> ${escapeHtml(s.name)}</div>
 <div class="school-del-meta">
 ${s.block ? `<span>${escapeHtml(s.block)}</span>` : ''}
 <span>${s.visitCount} visits</span>
 <span>${s.obsCount} obs</span>
 <span class="school-del-source">${escapeHtml(s.sources.join(', '))}</span>
 </div>
 </div>
 `).join('') + (filtered.length > 40 ? `<p style="text-align:center;color:var(--text-muted);font-size:11px;">...and ${filtered.length - 40} more</p>` : '');
  } else {
    listEl.innerHTML = '<p style="text-align:center;color:var(--text-muted);padding:16px;">No schools match current filters</p>';
  }

  btn.disabled = filtered.length === 0;
  countEl.textContent = filtered.length;
}

async function executeBulkDeleteSchools() {
  const filtered = getBulkDeleteSchoolsFiltered();
  if (filtered.length === 0) return;

  const totalVisits = filtered.reduce((s, x) => s + x.visitCount, 0);
  const totalObs = filtered.reduce((s, x) => s + x.obsCount, 0);

  if (!await showPopupConfirm({ title: 'Warning: Bulk Delete Schools', message: `Delete <strong>${filtered.length}</strong> schools?<br><br>This will permanently remove:<br> ${totalVisits} visit(s)<br> ${totalObs} observation(s)<br><br><strong>This CANNOT be undone!</strong>`, icon: 'fa-trash-alt', confirmText: `Delete ${filtered.length} Schools`, confirmColor: '#dc2626' })) return;

  const keysToDelete = new Set(filtered.map(s => s.key));

  // Remove visits
  let visits = DB.get('visits');
  visits = visits.filter(v => !keysToDelete.has((v.school || '').trim().toLowerCase()));
  DB.set('visits', visits);

  // Remove observations
  let observations = DB.get('observations');
  observations = observations.filter(o => !keysToDelete.has((o.school || '').trim().toLowerCase()));
  DB.set('observations', observations);

  closeModal('bulkDeleteSchoolsModal');
  _schoolDelInfos = [];
  renderSchoolProfiles();
  showToast(`Deleted ${filtered.length} schools (${totalVisits} visits, ${totalObs} observations removed)`, 'success', 5000);
}

// ===== SCHOOL PROFILES =====
function getSchoolData() {
  const visits = DB.get('visits');
  const observations = DB.get('observations');
  const schoolMap = {};

  const ensureSchool = (key, name, block) => {
    if (!schoolMap[key]) schoolMap[key] = { name, block: block || '', visits: [], observations: [], _dates: new Set(), _teachers: new Set() };
  };

  visits.forEach(v => {
    const key = (v.school || '').trim().toLowerCase();
    ensureSchool(key, (v.school || '').trim(), v.block);
    if (v.block && !schoolMap[key].block) schoolMap[key].block = v.block;
    if (v.cluster && !schoolMap[key].cluster) schoolMap[key].cluster = v.cluster.trim();
    schoolMap[key].visits.push(v);
    if (v.date) schoolMap[key]._dates.add(v.date);
  });

  observations.forEach(o => {
    const key = (o.school || '').trim().toLowerCase();
    ensureSchool(key, (o.school || '').trim(), o.block);
    if (o.block && !schoolMap[key].block) schoolMap[key].block = o.block;
    if (o.cluster && !schoolMap[key].cluster) schoolMap[key].cluster = o.cluster.trim();
    schoolMap[key].observations.push(o);
    if (o.date) schoolMap[key]._dates.add(o.date);
    const teacher = (o.teacher || '').trim();
    if (teacher) schoolMap[key]._teachers.add(teacher);
  });

  // Convert sets to counts for easy access
  Object.values(schoolMap).forEach(s => {
    s.totalVisitDays = s._dates.size;
    s.teacherCount = s._teachers.size;
    s.teachers = [...s._teachers];
    delete s._dates;
    delete s._teachers;
  });

  return schoolMap;
}

function exportSchoolDataExcel() {
  const schoolMap = getSchoolData();
  const schools = Object.values(schoolMap);
  if (schools.length === 0) {
    showToast('No school data to export', 'info');
    return;
  }

  const allStudentRecords = DB.get('schoolStudentRecords') || {};

  // Sort schools by name
  schools.sort((a, b) => a.name.localeCompare(b.name));

  // Get all active classes that have data across all schools to dynamically build columns
  const allPresentClasses = new Set();
  Object.values(allStudentRecords).forEach(sr => {
    if (sr && sr.classes) {
      Object.keys(sr.classes).forEach(c => allPresentClasses.add(c));
    }
  });

  const sortedClasses = [...allPresentClasses].sort((a, b) => {
    const numA = parseInt(a);
    const numB = parseInt(b);
    if (!isNaN(numA) && !isNaN(numB)) return numA - numB;
    return a.localeCompare(b);
  });

  const exportData = schools.map(s => {
    const schoolKey = s.name.trim().toLowerCase();
    let sr = allStudentRecords[schoolKey];
    if (Array.isArray(sr)) sr = { ...sr }; // Safety fallback
    const t = _ssrTotals(sr);

    // Base school metadata
    const row = {
      'School Name': s.name,
      'Block': s.block || '',
      'Cluster': s.cluster || '',
      'Total Visits': s.totalVisitDays,
      'Observations': s.observations.length,
      'Teachers Reached': s.teacherCount,
      'Total Students': t.total,
      'Total LIG (Level 1)': t.lig || 0,
      'Total FLN (Level 2)': t.fln || 0,
      'Total PGL (Level 3)': t.pgl || 0,
      'Total GL (Level 4)': t.gl || 0
    };

    // Class-wise totals
    sortedClasses.forEach(cls => {
      let classTotal = 0;
      if (sr && sr.classes && sr.classes[cls]) {
        const c = sr.classes[cls];
        classTotal = (c.lig || 0) + (c.fln || 0) + (c.pgl || 0) + (c.gl || 0);
      }
      row[`Class ${cls} Students`] = classTotal || '';
    });

    row['Notes'] = sr && sr.notes ? sr.notes : '';
    row['Last Updated'] = sr && sr.updatedAt ? new Date(sr.updatedAt).toLocaleDateString('en-IN') : '';

    return row;
  });

  const ws = XLSX.utils.json_to_sheet(exportData);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, 'Schools & Students Data');
  XLSX.writeFile(wb, `APF_School_Data_${new Date().toISOString().split('T')[0]}.xlsx`);
  showToast('Exported to Excel ', 'success');
}

function _schoolPopulateClusterFilter(schools) {
  const sel = document.getElementById('schoolClusterFilter');
  if (!sel) return;
  const cur = sel.value;
  const clusters = [...new Set(schools.map(s => s.cluster).filter(Boolean))].sort();
  sel.innerHTML = '<option value="all">All Clusters</option>' +
    clusters.map(c => `<option value="${escapeHtml(c)}"${c === cur ? ' selected' : ''}>${escapeHtml(c)}</option>`).join('');
  if (cur && clusters.includes(cur)) sel.value = cur;
}

function renderSchoolProfiles() {
  const schoolMap = getSchoolData();
  const searchTerm = (document.getElementById('schoolSearchInput').value || '').toLowerCase();
  const clusterFilter = document.getElementById('schoolClusterFilter')?.value || 'all';
  let schools = Object.values(schoolMap);

  // Populate cluster dropdown from all schools (before filter) preserves selection
  _schoolPopulateClusterFilter(schools);

  // Auto-reveal cluster filter bar when a filter is active
  const clusterSel = document.getElementById('schoolClusterFilter');
  if (clusterSel && clusterSel.value !== 'all') {
    clusterSel.classList.add('has-filter');
    clusterSel.closest('.school-search-bar')?.classList.add('show-cluster');
  } else if (clusterSel) {
    clusterSel.classList.remove('has-filter');
  }

  if (searchTerm) {
    schools = schools.filter(s =>
      s.name.toLowerCase().includes(searchTerm) ||
      (s.block || '').toLowerCase().includes(searchTerm) ||
      (s.cluster || '').toLowerCase().includes(searchTerm)
    );
  }
  if (clusterFilter !== 'all') {
    schools = schools.filter(s => (s.cluster || '') === clusterFilter);
  }

  // Sort by total activity (most active first)
  schools.sort((a, b) => (b.totalVisitDays + b.observations.length) - (a.totalVisitDays + a.observations.length));

  // Summary stats
  const allSchools = Object.values(schoolMap);
  const totalSchools = allSchools.length;
  const totalVisitDays = allSchools.reduce((s, sc) => s + sc.totalVisitDays, 0);
  const totalObs = allSchools.reduce((s, sc) => s + sc.observations.length, 0);
  const totalTeachers = new Set(allSchools.flatMap(sc => sc.teachers)).size;

  // Student totals
  let allStudents = DB.get('schoolStudentRecords') || {};
  if (Array.isArray(allStudents)) allStudents = { ...allStudents };
  let totalStudents = 0;
  Object.values(allStudents).forEach(sr => { totalStudents += _ssrTotals(sr).total; });

  document.getElementById('schoolSummaryStats').innerHTML = `
 <div class="school-summary-stat"><div class="stat-icon"><i class="fas fa-school"></i></div><div class="stat-value">${totalSchools}</div><div class="stat-label">Schools</div></div>
 <div class="school-summary-stat"><div class="stat-icon"><i class="fas fa-map-marker-alt"></i></div><div class="stat-value">${totalVisitDays}</div><div class="stat-label">Total Visits</div></div>
 <div class="school-summary-stat"><div class="stat-icon"><i class="fas fa-clipboard-list"></i></div><div class="stat-value">${totalObs}</div><div class="stat-label">Observations</div></div>
 <div class="school-summary-stat"><div class="stat-icon"><i class="fas fa-chalkboard-teacher"></i></div><div class="stat-value">${totalTeachers}</div><div class="stat-label">Teachers</div></div>
 <div class="school-summary-stat"><div class="stat-icon"><i class="fas fa-user-graduate"></i></div><div class="stat-value">${totalStudents}</div><div class="stat-label">Students</div></div>
 `;

  // Show school list (hide detail view)
  document.getElementById('schoolDetailView').style.display = 'none';
  const container = document.getElementById('schoolProfilesContainer');
  container.style.display = '';

  if (schools.length === 0) {
    container.innerHTML = '<div class="idea-empty"><i class="fas fa-school"></i><h3>No schools found</h3><p>Schools will appear here automatically from your visits and observations.</p></div>';
    return;
  }

  const pg = getPaginatedItems(schools, 'schools', getPageSize(18));
  let allStudentRecords = DB.get('schoolStudentRecords') || {};
  if (Array.isArray(allStudentRecords)) allStudentRecords = { ...allStudentRecords };

  container.innerHTML = `<div class="school-cards-grid">${pg.items.map(school => {
    // Last activity date from visits + observations combined
    const allDates = [
      ...school.visits.filter(v => v.date).map(v => v.date),
      ...school.observations.filter(o => o.date).map(o => o.date)
    ].sort();
    const lastDate = allDates.length > 0 ? allDates[allDates.length - 1] : null;
    const avgRating = school.observations.length > 0
      ? (school.observations.reduce((s, o) => s + (((o.engagementRating || o.engagement) || 0) + (o.methodology || 0) + (o.tlm || 0)) / 3, 0) / school.observations.length).toFixed(1)
      : null;
    const schoolKey = school.name.trim().toLowerCase();
    const safeKey = encodeURIComponent(schoolKey).replace(/'/g, '%27');

    // Student records summary
    const sr = allStudentRecords[schoolKey];
    const totalStudents = _ssrTotals(sr).total;
    const studentBadge = totalStudents > 0 ? `<div class="school-metric"><div class="metric-value">${totalStudents}</div><div class="metric-label">Students</div></div>` : '';
    const studentBar = totalStudents > 0 ? _buildLevelMiniBar(sr, totalStudents) : '';

    return `
 <div class="school-profile-card" onclick="showSchoolDetail('${safeKey}')">
 <div class="school-card-delete" onclick="event.stopPropagation(); deleteSchoolProfile('${safeKey}')" title="Delete this school"><i class="fas fa-times"></i></div>
 <div class="school-card-name"><i class="fas fa-school"></i> ${escapeHtml(school.name)}</div>
 <div class="school-card-block">${escapeHtml(school.block || 'Block not specified')}${school.cluster ? ` <span class="school-card-cluster"><i class="fas fa-layer-group"></i> ${escapeHtml(school.cluster)}</span>` : ''}</div>
 <div class="school-card-metrics">
 <div class="school-metric"><div class="metric-value">${school.totalVisitDays}</div><div class="metric-label">Visits</div></div>
 <div class="school-metric"><div class="metric-value">${school.observations.length}</div><div class="metric-label">Obs.</div></div>
 <div class="school-metric"><div class="metric-value">${school.teacherCount}</div><div class="metric-label">Teachers</div></div>
 ${studentBadge}
 </div>
 ${studentBar}
 <div class="school-card-footer">
 <div class="school-last-visit"><i class="fas fa-clock"></i> ${lastDate ? new Date(lastDate).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' }) : 'No activity'}</div>
 ${avgRating ? `<div class="school-rating"><i class="fas fa-star"></i> ${avgRating}/5</div>` : ''}
 </div>
 </div>
 `;
  }).join('')}</div>` + renderPaginationControls('schools', pg, 'renderSchoolProfiles');
}

