    defaultBlock: '',
    defaultCluster: '',
    defaultDistrict: '',
    defaultState: '',
    dateFormat: 'dd-mmm-yyyy',
    smartAlerts: true,
    dashCharts: true,
    recentActivity: true,
    startPage: 'dashboard',
    followupReminder: true,
    visitReminder: true,
    worklogAuto: true,
    saveToast: true,
    quickCapture: true,
    confirmDeletes: true,
    bulkDeleteEnabled: false,
    reduceMotion: false,
    splashEnabled: true,
    splashDuration: 2600,
    splashTheme: 'indigo',
    cardsPerPage: 'default',
    hiddenSections: [],
    ssrClasses: { '1': true, '2': true, '3': true, '4': true, '5': true, '6': true, '7': true, '8': true },
