// Feature 1: AI Visit Report Generator
async function generateAIVisitReport(visitId) {
  if (!SarvamAI.isConfigured()) { showToast('Configure Sarvam AI API key in Settings first', 'warning'); return; }
  const visits = DB.get('visits') || [];
  const v = visits.find(x => x.id === visitId);
  if (!v) { showToast('Visit not found', 'error'); return; }

  const btn = event?.target?.closest('button');
  if (btn) { btn.disabled = true; btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Generating...'; }

  const observations = (DB.get('observations') || []).filter(o => (o.school || '').toLowerCase() === (v.school || '').toLowerCase() && o.date === v.date);
  const profile = DB.get('userProfile') || {};

  const prompt = `Generate a detailed school visit report for submission to the Block Coordinator.

VISIT DATA:
- School: ${v.school || 'N/A'}
- Date: ${v.date || 'N/A'}
- Block: ${v.block || 'N/A'}, Cluster: ${v.cluster || 'N/A'}, District: ${v.district || 'N/A'}
- Purpose: ${v.purpose || 'General Visit'}
- Duration: ${v.duration || 'N/A'}
- Status: ${v.status || 'N/A'}
- HM Present: ${v.hmPresent || 'N/A'}
- Teachers Met: ${v.teachersMet || 'N/A'}
- People Met: ${v.peopleMet || 'N/A'}
- Classes Visited: ${v.classesVisited || 'N/A'}
- Students Observed: ${v.studentCount || 'N/A'}
- Activities Done: ${(v.activities || []).join(', ') || 'N/A'}
- Key Observations: ${v.notes || 'N/A'}
- Best Practices: ${v.bestPractices || 'N/A'}
- Challenges: ${v.challenges || 'N/A'}
- Infrastructure: ${v.infrastructure || 'N/A'}
- SDMC/Community: ${v.sdmc || 'N/A'}
- Materials Shared: ${v.materialsShared || 'N/A'}
- HM Discussion: ${v.hmDiscussion || 'N/A'}
- Follow-up: ${v.followUp || 'N/A'}
- Broader Plan: ${v.broaderPlan || 'N/A'}
- Rating: ${v.rating || 'N/A'}/5
${observations.length > 0 ? `\nCLASSROOM OBSERVATIONS DURING VISIT:\n${observations.map(o => `- Teacher: ${o.teacher || 'N/A'}, Subject: ${o.subject || 'N/A'}, Class: ${o.class || 'N/A'}, Engagement: ${o.engagementLevel || 'N/A'}, Practice: ${o.practice || 'N/A'}`).join('\n')}` : ''}

RESOURCE PERSON: ${profile.name || 'N/A'} (${profile.designation || 'Resource Person'})

Generate a professional visit report with these sections:
1. Visit Summary (date, school, purpose)
2. Key Observations & Findings
3. Teacher Interactions & Classroom Insights
4. Best Practices Noticed
5. Challenges & Areas of Concern
6. Action Items & Recommendations
7. Follow-up Plan

Format clearly with headers and bullet points. Keep it professional and actionable.`;

  try {
    const res = await SarvamAI.chat([
      { role: 'system', content: 'You are an expert report writer for Azim Premji Foundation. Generate clear, professional visit reports. Use Hindi/regional terms where common in Indian education context.' },
      { role: 'user', content: prompt }
    ], { temperature: 0.5, max_tokens: 3000 });
    const reply = res.choices?.[0]?.message?.content || 'Could not generate report.';
    showAIOutputModal('AI Visit Report ' + (v.school || ''), reply, visitId);
  } catch (err) {
    showToast('Error: ' + err.message, 'error');
  }
  if (btn) { btn.disabled = false; btn.innerHTML = '<i class="fas fa-robot"></i> AI Report'; }
}

