// Feature 4: School Health Score
async function generateSchoolHealthScore(schoolName) {
  if (!SarvamAI.isConfigured()) { showToast('Configure Sarvam AI API key in Settings first', 'warning'); return; }

  const btn = event?.target?.closest('button');
  if (btn) { btn.disabled = true; btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Analyzing...'; }

  const visits = (DB.get('visits') || []).filter(v => (v.school || '').toLowerCase() === schoolName.toLowerCase());
  const observations = (DB.get('observations') || []).filter(o => (o.school || '').toLowerCase() === schoolName.toLowerCase());
  const trainings = DB.get('trainings') || [];
  const followups = (DB.get('followupStatus') || []).filter(f => (f.school || '').toLowerCase() === schoolName.toLowerCase());

  const avgRating = visits.filter(v => v.rating).reduce((s, v) => s + Number(v.rating), 0) / (visits.filter(v => v.rating).length || 1);
  const engagementBreakdown = {};
  observations.forEach(o => { const e = o.engagementLevel || 'Unknown'; engagementBreakdown[e] = (engagementBreakdown[e] || 0) + 1; });

  const prompt = `Analyze this school's health based on all available data and provide a Health Score.

SCHOOL: ${schoolName}

VISIT DATA:
- Total visits: ${visits.length}
- Most recent visit: ${visits[0]?.date || 'Never'}
- Average rating: ${avgRating.toFixed(1)}/5
- Visit purposes: ${[...new Set(visits.map(v => v.purpose))].join(', ') || 'N/A'}
- Last 3 visit notes: ${visits.slice(0, 3).map(v => v.notes || 'No notes').join(' | ')}

OBSERVATION DATA:
- Total observations: ${observations.length}
- Teacher engagement: ${Object.entries(engagementBreakdown).map(([k, v]) => `${k}: ${v}`).join(', ') || 'N/A'}
- Unique teachers observed: ${new Set(observations.map(o => o.teacher).filter(Boolean)).size}
- Subjects covered: ${[...new Set(observations.map(o => o.subject).filter(Boolean))].join(', ') || 'N/A'}

FOLLOW-UP STATUS:
- Total follow-ups: ${followups.length}
- Completed: ${followups.filter(f => f.status === 'completed' || f.status === 'done').length}
- Pending: ${followups.filter(f => f.status !== 'completed' && f.status !== 'done').length}

Provide:
1. **School Health Score** (out of 100) with a brief justification
2. **Strengths** What's going well (2-3 points)
3. **Attention Areas** Where the school needs more support (2-3 points)
4. **Recommended Actions** Specific next steps (3-4 items)
5. **Visit Priority** Should this school be visited urgently? (High/Medium/Low)`;

  try {
    const res = await SarvamAI.chat([
      { role: 'system', content: 'You are an education data analyst for Azim Premji Foundation. Analyze school data and provide actionable health scores. Be data-driven but practical.' },
      { role: 'user', content: prompt }
    ], { temperature: 0.5, max_tokens: 2000 });
    const reply = res.choices?.[0]?.message?.content || 'Could not generate health score.';
    showAIOutputModal('School Health ' + schoolName, reply);
  } catch (err) {
    showToast('Error: ' + err.message, 'error');
  }
  if (btn) { btn.disabled = false; btn.innerHTML = '<i class="fas fa-heartbeat"></i> Health Score'; }
}

// Feature 5: AI Weekly Plan Generator
async function generateAIWeeklyPlan() {
  if (!SarvamAI.isConfigured()) { showToast('Configure Sarvam AI API key in Settings first', 'warning'); return; }

  const btn = event?.target?.closest('button');
  if (btn) { btn.disabled = true; btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Generating Plan...'; }

  const visits = DB.get('visits') || [];
  const followups = DB.get('followupStatus') || [];
  const tasks = DB.get('plannerTasks') || [];
  const observations = DB.get('observations') || [];
  const trainings = DB.get('trainings') || [];
  const profile = DB.get('userProfile') || {};

  const now = new Date();
  const weekStart = new Date(now);
  weekStart.setDate(now.getDate() - now.getDay() + 1); // Monday
  const weekEnd = new Date(weekStart);
  weekEnd.setDate(weekStart.getDate() + 6);

  const pendingFollowups = followups.filter(f => f.status !== 'completed' && f.status !== 'done');
  const schoolFreq = {};
  visits.forEach(v => { const s = v.school || ''; schoolFreq[s] = (schoolFreq[s] || 0) + 1; });
  const leastVisited = Object.entries(schoolFreq).sort((a, b) => a[1] - b[1]).slice(0, 5);
  const upcomingTrainings = trainings.filter(t => t.date >= now.toISOString().split('T')[0] && t.status === 'upcoming');

  const prompt = `Generate a practical weekly plan for an APF Resource Person for the week of ${weekStart.toLocaleDateString('en-IN')} to ${weekEnd.toLocaleDateString('en-IN')}.

CONTEXT:
- Name: ${profile.name || 'Resource Person'}, Block: ${profile.block || 'N/A'}
- Total schools covered: ${Object.keys(schoolFreq).length}
- Pending follow-ups: ${pendingFollowups.length}
${pendingFollowups.slice(0, 5).map(f => ` - ${f.title || f.description || 'Untitled'} (${f.status})`).join('\n')}

SCHOOLS NEEDING VISITS (least visited):
${leastVisited.map(([s, c]) => `- ${s}: only ${c} visit(s)`).join('\n') || '- All schools well-covered'}

UPCOMING TRAININGS:
${upcomingTrainings.map(t => `- ${t.title} on ${t.date}`).join('\n') || '- None scheduled'}

EXISTING TASKS THIS WEEK:
${tasks.filter(t => t.date >= weekStart.toISOString().split('T')[0] && t.date <= weekEnd.toISOString().split('T')[0]).map(t => `- ${t.date}: ${t.title || t.description || 'Untitled'}`).join('\n') || '- None planned yet'}

RECENT OBSERVATIONS:
${observations.slice(0, 5).map(o => `- ${o.school}, Teacher: ${o.teacher}, Engagement: ${o.engagementLevel}`).join('\n') || '- None'}

Generate a day-by-day plan (Monday to Saturday) with:
- 1-2 main activities per day (school visits, meetings, training prep, desk work)
- Specific schools to visit with reasons
- Follow-ups to address
- Time allocations (First Half / Second Half / Full Day)

Format as a clear, easy-to-follow daily schedule. Be realistic about travel time and workload.`;

  try {
    const res = await SarvamAI.chat([
      { role: 'system', content: 'You are a productivity coach for field-based education Resource Persons in India. Create realistic, actionable weekly plans that balance school visits, follow-ups, trainings, and desk work.' },
      { role: 'user', content: prompt }
    ], { temperature: 0.6, max_tokens: 2500 });
    const reply = res.choices?.[0]?.message?.content || 'Could not generate plan.';
    showAIOutputModal('AI Weekly Plan', reply);
  } catch (err) {
    showToast('Error: ' + err.message, 'error');
  }
  if (btn) { btn.disabled = false; btn.innerHTML = '<i class="fas fa-robot"></i> AI Weekly Plan'; }
}

// Feature 6: AI Training Effectiveness Analysis
async function generateAITrainingSummary() {
  if (!SarvamAI.isConfigured()) { showToast('Configure Sarvam AI API key in Settings first', 'warning'); return; }
  const btn = event?.target?.closest('button');
  if (btn) { btn.disabled = true; btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Analyzing...'; }

  const trainings = DB.get('trainings') || [];
  const profile = DB.get('userProfile') || {};

  if (trainings.length === 0) {
    showToast('No training data available', 'warning');
    if (btn) { btn.disabled = false; btn.innerHTML = '<i class="fas fa-robot"></i> AI Summary'; }
    return;
  }

  const completed = trainings.filter(t => t.status === 'completed');
  const upcoming = trainings.filter(t => t.status === 'upcoming');
  const totalAttendees = trainings.reduce((sum, t) => sum + (t.attendees || (t.participants || []).length || 0), 0);
  const topics = [...new Set(trainings.map(t => t.topic || t.title).filter(Boolean))];

  const trainingSummary = trainings.slice(0, 15).map(t =>
    `- "${(t.title || t.topic || 'Untitled').substring(0, 50)}" | Date: ${t.date || 'N/A'} | Status: ${t.status || 'N/A'} | Attendees: ${t.attendees || (t.participants || []).length || 'N/A'} | Duration: ${t.duration || 'N/A'} | Location: ${t.location || t.venue || 'N/A'}`
  ).join('\n');

  const prompt = `Analyze the teacher training program and provide an effectiveness summary.

Resource Person: ${profile.name || 'N/A'}, Block: ${profile.block || 'N/A'}

TRAINING OVERVIEW:
- Total trainings: ${trainings.length}
- Completed: ${completed.length}
- Upcoming: ${upcoming.length}
- Total attendees across all sessions: ${totalAttendees}
- Topics covered: ${topics.join(', ') || 'N/A'}

RECENT TRAINING DETAILS:
${trainingSummary}

Provide:
1. **Training Program Overview** Summary of the training effort
2. **Effectiveness Analysis** What's working well and what isn't
3. **Coverage Analysis** Are enough teachers being reached? Topic diversity?
4. **Recommendations** Specific suggestions for improving training impact
5. **Suggested Next Trainings** 3-4 training topics based on gaps identified
6. **Key Metrics to Track** What should be measured going forward

Be practical and specific.`;

  try {
    const res = await SarvamAI.chat([
      { role: 'system', content: 'You are a teacher training effectiveness analyst at Azim Premji Foundation. Analyze training programs and provide actionable insights for Resource Persons to improve teacher development impact.' },
      { role: 'user', content: prompt }
    ], { temperature: 0.5, max_tokens: 2500 });
    const reply = res.choices?.[0]?.message?.content || 'Could not generate summary.';
    showAIOutputModal('AI Training Analysis', reply);
  } catch (err) {
    showToast('Error: ' + err.message, 'error');
  }
  if (btn) { btn.disabled = false; btn.innerHTML = '<i class="fas fa-robot"></i> AI Summary'; }
}

