// Feature 9: AI Goal Progress Insights
async function generateAIGoalInsights() {
  if (!SarvamAI.isConfigured()) { showToast('Configure Sarvam AI API key in Settings first', 'warning'); return; }
  const btn = event?.target?.closest('button');
  if (btn) { btn.disabled = true; btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Analyzing...'; }

  const profile = DB.get('userProfile') || {};
  const goals = DB.get('goalTargets') || {};
  const visits = DB.get('visits') || [];
  const observations = DB.get('observations') || [];
  const trainings = DB.get('trainings') || [];
  const resources = DB.get('resources') || [];

  // Get current month
  const monthSel = document.getElementById('goalMonth');
  const selectedMonth = monthSel?.value || new Date().toISOString().slice(0, 7);
  const monthGoals = goals[selectedMonth] || {};

  // Calculate actuals
  const monthVisits = visits.filter(v => (v.date || '').startsWith(selectedMonth) && v.status === 'completed').length;
  const monthTrainings = trainings.filter(t => (t.date || '').startsWith(selectedMonth) && t.status === 'completed').length;
  const monthObs = observations.filter(o => (o.date || '').startsWith(selectedMonth)).length;
  const monthTeachers = new Set(observations.filter(o => (o.date || '').startsWith(selectedMonth)).map(o => o.teacher).filter(Boolean)).size;
  const monthResources = resources.filter(r => (r.dateAdded || '').startsWith(selectedMonth)).length;

  const goalsData = {
    visits: { target: monthGoals.visits || 15, actual: monthVisits },
    trainings: { target: monthGoals.trainings || 4, actual: monthTrainings },
    observations: { target: monthGoals.observations || 10, actual: monthObs },
    teachers: { target: monthGoals.teachers || 50, actual: monthTeachers },
    resources: { target: monthGoals.resources || 5, actual: monthResources }
  };

  // Calculate days remaining
  const now = new Date();
  const monthEnd = new Date(now.getFullYear(), now.getMonth() + 1, 0);
  const daysRemaining = Math.max(0, Math.ceil((monthEnd - now) / (1000 * 60 * 60 * 24)));

  const prompt = `Analyze the goal progress for this Resource Person and provide actionable insights.

Resource Person: ${profile.name || 'N/A'}, Block: ${profile.block || 'N/A'}
Month: ${selectedMonth}
Days remaining in month: ${daysRemaining}

GOAL PROGRESS:
${Object.entries(goalsData).map(([key, val]) => {
    const pct = val.target > 0 ? Math.round((val.actual / val.target) * 100) : 0;
    return `- ${key}: ${val.actual}/${val.target} (${pct}%)`;
  }).join('\n')}

Provide:
1. **Progress Overview** Where does the person stand overall?
2. **Goals at Risk** Which goals are unlikely to be met at current pace? Include calculations.
3. **On Track** Which goals are going well?
4. **Daily Targets** What should the person aim for each remaining day to meet targets?
5. **Smart Adjustments** Should any targets be revised? Why?
6. **Motivation** An encouraging note about progress made so far

Be specific with numbers and realistic about what's achievable.`;

  try {
    const res = await SarvamAI.chat([
      { role: 'system', content: 'You are a productivity coach for field-based education Resource Persons at Azim Premji Foundation. Analyze goal progress with data-driven insights. Be honest about challenges but encouraging about progress. Always provide specific, actionable advice.' },
      { role: 'user', content: prompt }
    ], { temperature: 0.5, max_tokens: 2000 });
    const reply = res.choices?.[0]?.message?.content || 'Could not generate insights.';
    showAIOutputModal('AI Goal Insights ' + selectedMonth, reply);
  } catch (err) {
    showToast('Error: ' + err.message, 'error');
  }
  if (btn) { btn.disabled = false; btn.innerHTML = '<i class="fas fa-robot"></i> AI Insights'; }
}

// Feature 10: AI Observation Smart Planner
async function generateAIObservationPlanner() {
  if (!SarvamAI.isConfigured()) { showToast('Configure Sarvam AI API key in Settings first', 'warning'); return; }
  const btn = event?.target?.closest('button');
  if (btn) { btn.disabled = true; btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Planning...'; }

  const observations = DB.get('observations') || [];
  const visits = DB.get('visits') || [];
  const profile = DB.get('userProfile') || {};

  if (observations.length === 0) {
    showToast('No observation data available to analyze', 'warning');
    if (btn) { btn.disabled = false; btn.innerHTML = '<i class="fas fa-brain"></i> AI Smart Planner'; }
    return;
  }

  // Build comprehensive stats
  const schools = {};
  const teachers = {};
  const subjects = {};
  const engagementCounts = {};

  observations.forEach(o => {
    const s = o.school || 'Unknown';
    const t = o.teacher || 'Unknown';
    const sub = o.subject || 'Unknown';
    const eng = o.engagementLevel || 'Unknown';

    if (!schools[s]) schools[s] = { count: 0, lastDate: '', teachers: new Set(), cluster: o.cluster || '' };
    schools[s].count++;
    if (o.date > schools[s].lastDate) schools[s].lastDate = o.date;
    schools[s].teachers.add(t);

    if (!teachers[t]) teachers[t] = { count: 0, lastDate: '', school: s, engagement: [], yesCount: 0 };
    teachers[t].count++;
    if (o.date > teachers[t].lastDate) teachers[t].lastDate = o.date;
    teachers[t].engagement.push(eng);
    if ((o.observationStatus || '') === 'Yes') teachers[t].yesCount++;

    subjects[sub] = (subjects[sub] || 0) + 1;
    engagementCounts[eng] = (engagementCounts[eng] || 0) + 1;
  });

  const totalSchools = Object.keys(schools).length;
  const totalTeachers = Object.keys(teachers).length;
  const avgObsPerTeacher = totalTeachers > 0 ? (observations.length / totalTeachers).toFixed(1) : 0;

  // Find schools needing visits (oldest visit dates)
  const schoolsByRecency = Object.entries(schools)
    .sort((a, b) => (a[1].lastDate || '').localeCompare(b[1].lastDate || ''))
    .slice(0, 10)
    .map(([name, d]) => `- ${name}: ${d.count} obs, last: ${d.lastDate || 'Never'}, teachers: ${d.teachers.size}, cluster: ${d.cluster}`)
    .join('\n');

  // Find teachers needing attention (least observed, low engagement)
  const teachersByNeed = Object.entries(teachers)
    .sort((a, b) => a[1].count - b[1].count)
    .slice(0, 10)
    .map(([name, d]) => `- ${name} (${d.school}): ${d.count} obs, last: ${d.lastDate}, engagement: ${d.engagement.slice(-3).join(',')}${d.yesCount > 0 ? ', adopted: ' + d.yesCount : ''}`)
    .join('\n');

  // Recent visits for context
  const recentVisits = visits.slice(0, 5).map(v => `- ${v.school} on ${v.date} (${v.purpose || 'Visit'})`).join('\n');

  const prompt = `You are a Smart Field Planner for an APF Resource Person. Based on the observation data, generate a comprehensive observation plan.

RESOURCE PERSON: ${profile.name || 'N/A'}, Block: ${profile.block || 'N/A'}

OBSERVATION OVERVIEW:
- Total observations: ${observations.length}
- Schools covered: ${totalSchools}
- Teachers observed: ${totalTeachers}
- Avg observations per teacher: ${avgObsPerTeacher}
- Subjects: ${Object.entries(subjects).map(([k, v]) => `${k}(${v})`).join(', ')}
- Engagement distribution: ${Object.entries(engagementCounts).map(([k, v]) => `${k}: ${v}`).join(', ')}

SCHOOLS NEEDING PRIORITY VISITS (least recently observed):
${schoolsByRecency}

TEACHERS NEEDING MORE SUPPORT (least observed):
${teachersByNeed}

RECENT SCHOOL VISITS:
${recentVisits || 'None recorded'}

Generate a practical Smart Observation Plan covering:

1. **Priority Schools This Week** Top 5 schools to visit with specific reasons and which teachers to focus on
2. **Teacher Coaching Priorities** Top 5 teachers needing immediate support, with suggested coaching approach for each
3. **Practice Gap Analysis** Which subjects/areas are under-observed? What to look for.
4. **Weekly Observation Schedule** Day-by-day plan (Mon-Sat) with specific schools, teachers, and observation focus areas
5. **Quick Wins** 3 easy actions that would immediately improve observation coverage
6. **Monthly Targets** Suggested targets for next 30 days (# of observations, schools, teachers)

Be specific name actual schools and teachers. Make the plan actionable and realistic for field work.`;

  try {
    const res = await SarvamAI.chat([
      { role: 'system', content: 'You are an expert field planning assistant for Azim Premji Foundation Resource Persons. Generate data-driven, practical observation plans that prioritize schools and teachers needing the most support. Be specific with names, dates, and actions. Format with clear headings and bullet points.' },
      { role: 'user', content: prompt }
    ], { temperature: 0.5, max_tokens: 3000 });
    const reply = res.choices?.[0]?.message?.content || 'Could not generate plan.';
    showAIOutputModal('AI Smart Observation Planner', reply);
  } catch (err) {
    showToast('Error: ' + err.message, 'error');
  }
  if (btn) { btn.disabled = false; btn.innerHTML = '<i class="fas fa-brain"></i> AI Smart Planner'; }
}

// Feature 10: Voice-to-Text (Speech-to-Text)
let _voiceRecorder = null;
let _voiceRecording = false;
let _voiceTargetField = null;

async function toggleVoiceRecording(targetFieldId, lang) {
  _voiceTargetField = targetFieldId;
  const targetField = document.getElementById(targetFieldId);
  if (!targetField) { showToast('Target field not found', 'error'); return; }

  if (_voiceRecording) {
    // Stop recording
    _voiceRecording = false;
    if (_voiceRecorder && _voiceRecorder.state === 'recording') {
      _voiceRecorder.stop();
    }
    return;
  }

  if (!SarvamAI.isConfigured()) { showToast('Configure Sarvam AI API key in Settings first', 'warning'); return; }

  try {
    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
    const mediaRecorder = new MediaRecorder(stream, { mimeType: 'audio/webm' });
    _voiceRecorder = mediaRecorder;
    _voiceRecording = true;

    const chunks = [];
    mediaRecorder.ondataavailable = (e) => { if (e.data.size > 0) chunks.push(e.data); };

    mediaRecorder.onstop = async () => {
      stream.getTracks().forEach(t => t.stop());
      const allBtns = document.querySelectorAll('.ai-voice-btn.recording');
      allBtns.forEach(b => { b.classList.remove('recording'); b.innerHTML = '<i class="fas fa-microphone"></i>'; });

      if (chunks.length === 0) return;
      const blob = new Blob(chunks, { type: 'audio/webm' });

      // Convert to base64
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64 = reader.result.split(',')[1];
        const field = document.getElementById(_voiceTargetField);
        if (field) {
          const prevVal = field.value;
          field.value = prevVal + (prevVal ? '\n' : '') + ' Transcribing...';
        }
        try {
          const settings = getAppSettings();
          const sttLang = lang || settings.sarvamDefaultLang || 'hi-IN';
          const res = await SarvamAI.speechToText(base64, sttLang);
          const transcript = res.transcript || '';
          if (field) {
            field.value = prevVal + (prevVal ? '\n' : '') + transcript;
            field.dispatchEvent(new Event('input'));
          }
          if (transcript) showToast('Voice transcribed successfully!', 'success');
          else showToast('Could not transcribe audio', 'warning');
        } catch (err) {
          if (field) field.value = prevVal;
          showToast('STT Error: ' + err.message, 'error');
        }
      };
      reader.readAsDataURL(blob);
    };

    mediaRecorder.start();

    // Update button UI
    const btn = event?.target?.closest('.ai-voice-btn');
    if (btn) { btn.classList.add('recording'); btn.innerHTML = '<i class="fas fa-stop"></i>'; }

    showToast(' Recording... Click again to stop', 'info');

    // Auto-stop after 30 seconds
    setTimeout(() => {
      if (_voiceRecording && mediaRecorder.state === 'recording') {
        _voiceRecording = false;
        mediaRecorder.stop();
        showToast('Recording auto-stopped (30s limit)', 'info');
      }
    }, 30000);
  } catch (err) {
    showToast('Microphone error: ' + err.message, 'error');
    _voiceRecording = false;
  }
}

// Feature 7: AI Dashboard Digest
async function generateDashboardDigest() {
  if (!SarvamAI.isConfigured()) return;

  const digestEl = document.getElementById('aiDashboardDigest');
  if (!digestEl) return;

  digestEl.innerHTML = '<div style="text-align:center;padding:16px;color:var(--text-secondary);"><i class="fas fa-spinner fa-spin"></i> Generating AI digest...</div>';
  digestEl.style.display = 'block';

  const context = buildDataContext();
  const visits = DB.get('visits') || [];
  const followups = DB.get('followupStatus') || [];
  const observations = DB.get('observations') || [];

  const now = new Date();
  const today = now.toISOString().split('T')[0];
  const weekAgo = new Date(now - 7 * 86400000).toISOString().split('T')[0];
  const todayVisits = visits.filter(v => v.date === today);
  const weekVisits = visits.filter(v => v.date >= weekAgo);
  const overdueFollowups = followups.filter(f => f.status !== 'completed' && f.status !== 'done' && f.dueDate && f.dueDate < today);

  const prompt = `Generate a brief daily digest (3-5 bullet points) for an APF Resource Person based on their data. Today is ${now.toLocaleDateString('en-IN', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}.

DATA SUMMARY:
${context}

TODAY: ${todayVisits.length > 0 ? todayVisits.map(v => `Visit to ${v.school} (${v.status})`).join(', ') : 'No visits scheduled today'}
THIS WEEK: ${weekVisits.length} visits
OVERDUE FOLLOW-UPS: ${overdueFollowups.length}
RECENT OBSERVATIONS: ${observations.slice(0, 3).map(o => `${o.school} - ${o.teacher || 'Unknown'} (${o.engagementLevel || 'N/A'})`).join(', ') || 'None'}

Write 3-5 short, actionable bullet points covering:
- Today's priorities
- Pending items needing attention
- A brief performance insight
- One motivational note

Keep each point under 15 words. Be specific, not generic. Start every bullet point with a relevant emoji (e.g. 📋, 🏫, ⚠️, 📊, 💪, ✅, 🔔).`;

  try {
    const res = await SarvamAI.chat([
      { role: 'system', content: 'You are a brief, helpful daily planner AI. Write very concise bullet points. No headers or long sentences. You MUST start every bullet point with a relevant emoji. Format: "- 🏫 Your point here".' },
      { role: 'user', content: prompt }
    ], { temperature: 0.7, max_tokens: 1500 });
    const reply = res.choices?.[0]?.message?.content || 'No digest available.';
    digestEl.innerHTML = `<div class="ai-digest-header"><i class="fas fa-robot"></i> AI Digest <button class="btn btn-sm btn-ghost" onclick="generateDashboardDigest()" title="Refresh"><i class="fas fa-sync-alt"></i></button></div><div class="ai-digest-body">${formatAIResponse(reply)}</div>`;
  } catch (err) {
    digestEl.innerHTML = '<div style="padding:12px;font-size:12px;color:var(--text-muted);"><i class="fas fa-info-circle"></i> AI digest unavailable</div>';
  }
}

// Shared: AI output modal for visit reports, coach notes, etc.
function showAIOutputModal(title, content, relatedId) {
  let modal = document.getElementById('aiOutputModal');
  if (!modal) {
    modal = document.createElement('div');
    modal.className = 'modal-overlay';
    modal.id = 'aiOutputModal';
    modal.innerHTML = `<div class="modal" style="max-width:720px;">
 <div class="modal-header">
 <h2 id="aiOutputModalTitle"><i class="fas fa-robot"></i> AI Output</h2>
 <button class="modal-close" onclick="closeModal('aiOutputModal')"><i class="fas fa-times"></i></button>
 </div>
 <div class="modal-body" style="max-height:70vh;overflow-y:auto;">
 <div id="aiOutputModalBody" class="ai-output-content"></div>
 </div>
 <div class="modal-footer">
 <button class="btn btn-outline" onclick="copyAIOutput()"><i class="fas fa-copy"></i> Copy</button>
 <button class="btn btn-ghost" onclick="closeModal('aiOutputModal')">Close</button>
 </div>
 </div>`;
    document.body.appendChild(modal);
  }
  document.getElementById('aiOutputModalTitle').innerHTML = '<i class="fas fa-robot"></i> ' + escapeHtml(title);
  document.getElementById('aiOutputModalBody').innerHTML = '<div class="ai-insight-text">' + formatAIResponse(content) + '</div>';
  modal.classList.add('active');
}

function copyAIOutput() {
  const body = document.getElementById('aiOutputModalBody')?.innerText;
  if (body) navigator.clipboard.writeText(body).then(() => showToast('Copied to clipboard!', 'success'));
}

