let _guideStep = 0;

function showUserGuide(isFirstUse) {
  _guideStep = 0;
  renderGuideStep();
  document.getElementById('userGuideModal').classList.add('active');
  if (isFirstUse) {
    localStorage.setItem('apf_guide_shown', '1');
  }
}

function closeUserGuide() {
  document.getElementById('userGuideModal').classList.remove('active');
}

function guideNav(dir) {
  _guideStep += dir;
  if (_guideStep < 0) _guideStep = 0;
  if (_guideStep >= USER_GUIDE_STEPS.length) {
    closeUserGuide();
    showToast('You\'re all set! Explore the dashboard ', 'success');
    return;
  }
  renderGuideStep();
}

function renderGuideStep() {
  const step = USER_GUIDE_STEPS[_guideStep];
  const body = document.getElementById('guideBody');
  body.innerHTML = `
 <div class="guide-step">
 <div class="guide-step-icon" style="background:${step.color}20;color:${step.color};">
 <i class="fas ${step.icon}"></i>
 </div>
 <div class="guide-step-num">Step ${_guideStep + 1} of ${USER_GUIDE_STEPS.length}</div>
 <h3 class="guide-step-title">${step.title}</h3>
 <p class="guide-step-desc">${step.desc}</p>
 </div>
 `;
  // Dots
  const dots = document.getElementById('guideDots');
  dots.innerHTML = USER_GUIDE_STEPS.map((_, i) =>
    `<span class="guide-dot ${i === _guideStep ? 'active' : ''}" onclick="_guideStep=${i};renderGuideStep();"></span>`
  ).join('');
  // Buttons
  document.getElementById('guidePrevBtn').style.visibility = _guideStep === 0 ? 'hidden' : 'visible';
  const nextBtn = document.getElementById('guideNextBtn');
  if (_guideStep === USER_GUIDE_STEPS.length - 1) {
    nextBtn.innerHTML = '<i class="fas fa-check"></i> Got It!';
  } else {
    nextBtn.innerHTML = 'Next <i class="fas fa-arrow-right"></i>';
  }
}

// ===== Beforeunload save to file + cache =====
window.addEventListener('beforeunload', (e) => {
  if (hasUnsavedChanges && _sessionPassword) {
    // Best-effort saves (fire-and-forget)
    if (FileLink.isLinked()) FileLink.writeToFile(_sessionPassword);
    EncryptedCache.save(_sessionPassword);
  }
});

async function proceedAfterLicense() {
  // Restore persisted file handle from IndexedDB
  if (FileLink.isSupported()) {
    await FileLink.restoreHandle();
  }

  if (PasswordManager.isPasswordSet()) {
    // Try to auto-restore session (page refresh skip lock screen)
    const savedPwd = SessionPersist.restore();
    if (savedPwd) {
      const hash = await PasswordManager.hashPassword(savedPwd);
      if (hash === PasswordManager.getStoredHash()) {
        _sessionPassword = savedPwd;
        // Auto-load data silently
        let loaded = false;
        if (FileLink.isLinked()) {
          try {
            const data = await FileLink.readFromFile(savedPwd);
            if (data && data._meta && data._meta.app === 'APF Dashboard') {
              DB.clear();
              ENCRYPTED_DATA_KEYS.forEach(k => {
                if (data[k] !== undefined && typeof data[k] === 'object' && data[k] !== null) _originalDBSet(k, data[k]);
              });
              lastEncSaveTime = EncryptedCache.getLastSaveTime();
              clearUnsavedChanges();
              loaded = true;
            }
          } catch (err) { console.error('Auto-restore file read failed:', err); }
        }
        if (!loaded && EncryptedCache.exists()) {
          try {
            const data = await EncryptedCache.load(savedPwd);
            if (data && data._meta && data._meta.app === 'APF Dashboard') {
              DB.clear();
              ENCRYPTED_DATA_KEYS.forEach(k => {
                if (data[k] !== undefined && typeof data[k] === 'object' && data[k] !== null) _originalDBSet(k, data[k]);
              });
              lastEncSaveTime = EncryptedCache.getLastSaveTime();
              clearUnsavedChanges();
              loaded = true;
            }
          } catch (err) { console.error('Auto-restore cache failed:', err); EncryptedCache.clear(); }
        }
        if (loaded) {
          isAppUnlocked = true;
          initApp();
          startPeriodicSave();
          return; // Session restored no lock screen needed
        }
        // Session token invalid now, clear it
        SessionPersist.clear();
      } else {
        SessionPersist.clear();
      }
    }
    // No valid session show lock screen
    showLockScreen('unlock');
  } else if (EncryptedCache.exists()) {
    EncryptedCache.clear();
    showWelcomeScreen();
  } else {
    // Check localStorage fallback for previously saved data (no password scenario)
    const restoredCount = restoreFromLocalStorage();
    if (restoredCount > 0) {
      hideWelcomeScreen();
      isAppUnlocked = true;
      initApp();
      showToast(`Restored your data from local backup (${restoredCount} categories). Set a password for secure saving!`, 'info');
      return;
    }
    showWelcomeScreen();
  }
}

// ===== Reflective Report for Visits & Trainings =====

function openReflectiveReport(type, id) {
  document.getElementById('rrEntryType').value = type;
  document.getElementById('rrEntryId').value = id;
  document.getElementById('rrForm').reset();
  document.getElementById('rrDate').value = new Date().toISOString().split('T')[0];

  const dbKey = type === 'training' ? 'trainings' : 'visits';
  const entries = DB.get(dbKey) || [];
  const entry = entries.find(e => e.id === id);
  if (!entry) { showToast('Entry not found', 'error'); return; }

  // Context banner
  const banner = document.getElementById('rrContextBanner');
  if (type === 'training') {
    banner.innerHTML = `<div class="rr-context"><i class="fas fa-chalkboard-teacher" style="color:#8b5cf6"></i><div><strong>${escapeHtml(entry.title)}</strong><span>${new Date(entry.date).toLocaleDateString('en-IN')} ${entry.duration || ''}h ${entry.attendees || '?'} attendees${entry.venue ? ' ' + escapeHtml(entry.venue) : ''}</span></div></div>`;
    document.getElementById('rrModalTitle').innerHTML = '<i class="fas fa-file-signature"></i> Training Reflective Report';
  } else {
    const visitDate = new Date(entry.date).toLocaleDateString('en-IN', { day: '2-digit', month: 'long', year: 'numeric' });
    const ratingStars = entry.rating ? ''.repeat(parseInt(entry.rating)) : '';
    banner.innerHTML = `<div class="rr-context"><i class="fas fa-school" style="color:#6366f1"></i><div><strong>${escapeHtml(entry.school || 'School Visit')}</strong><span>${visitDate} ${escapeHtml(entry.purpose || '')}${entry.block ? ' ' + escapeHtml(entry.block) : ''}</span></div></div>
 <div class="rr-visit-details">
 <div class="rr-visit-detail"><span class="rr-vd-label"><i class="fas fa-map-marker-alt"></i> Block / Cluster</span><span class="rr-vd-value">${escapeHtml(entry.block || '')} / ${escapeHtml(entry.cluster || '')}</span></div>
 <div class="rr-visit-detail"><span class="rr-vd-label"><i class="fas fa-bullseye"></i> Purpose</span><span class="rr-vd-value">${escapeHtml(entry.purpose || '')}</span></div>
 <div class="rr-visit-detail"><span class="rr-vd-label"><i class="fas fa-clock"></i> Duration</span><span class="rr-vd-value">${entry.duration || ''}</span></div>
 <div class="rr-visit-detail"><span class="rr-vd-label"><i class="fas fa-flag"></i> Status</span><span class="rr-vd-value">${escapeHtml(entry.status || '')}</span></div>
 ${entry.peopleMet ? `<div class="rr-visit-detail rr-vd-full"><span class="rr-vd-label"><i class="fas fa-users"></i> People Met</span><span class="rr-vd-value">${escapeHtml(entry.peopleMet)}</span></div>` : ''}
 ${ratingStars ? `<div class="rr-visit-detail"><span class="rr-vd-label"><i class="fas fa-star"></i> Visit Rating</span><span class="rr-vd-value">${ratingStars}</span></div>` : ''}
 ${entry.notes ? `<div class="rr-visit-detail rr-vd-full"><span class="rr-vd-label"><i class="fas fa-sticky-note"></i> Notes</span><span class="rr-vd-value">${escapeHtml(entry.notes)}</span></div>` : ''}
 ${entry.followUp ? `<div class="rr-visit-detail rr-vd-full"><span class="rr-vd-label"><i class="fas fa-redo"></i> Follow-up</span><span class="rr-vd-value">${escapeHtml(entry.followUp)}</span></div>` : ''}
 ${entry.nextDate ? `<div class="rr-visit-detail"><span class="rr-vd-label"><i class="fas fa-calendar-alt"></i> Next Visit</span><span class="rr-vd-value">${new Date(entry.nextDate).toLocaleDateString('en-IN')}</span></div>` : ''}
 </div>`;
    document.getElementById('rrModalTitle').innerHTML = '<i class="fas fa-file-signature"></i> Visit Reflective Report';
  }

  // Auto-populate teachers list from attendance data
  const teachersList = document.getElementById('rrTeachersList');
  const attendees = (type === 'training') ? (entry.attendanceList || []) : [];
  const visitTeachers = (type === 'visit') ? (entry.peopleMet || entry.teachersMet || '') : '';

  if (type === 'training' && attendees.length > 0) {
    teachersList.innerHTML = `<table class="rr-teachers-table">
 <thead><tr><th>#</th><th>Name</th><th>School</th><th>Designation</th></tr></thead>
 <tbody>${attendees.map((a, i) => `<tr><td>${i + 1}</td><td>${escapeHtml(a.name || '')}</td><td>${escapeHtml(a.school || '')}</td><td>${escapeHtml(a.designation || '')}</td></tr>`).join('')}</tbody>
 </table>
 <div style="font-size:12px;color:var(--text-muted);margin-top:6px;"><i class="fas fa-info-circle"></i> ${attendees.length} teacher(s) from attendance records</div>`;
  } else if (type === 'visit' && visitTeachers) {
    teachersList.innerHTML = `<div class="rr-visit-teachers"><i class="fas fa-users" style="color:var(--text-muted);margin-right:6px"></i>${escapeHtml(visitTeachers)}</div>`;
  } else {
    teachersList.innerHTML = `<div style="padding:12px;text-align:center;color:var(--text-muted);font-size:13px;"><i class="fas fa-user-slash"></i> ${type === 'training' ? 'No attendance recorded yet. Add attendance from the training card first.' : 'No teachers recorded for this visit.'}</div>`;
  }

  // Load existing report if any
  const rr = entry.reflectiveReport;
  if (rr) {
    document.getElementById('rrWhatWentWell').value = rr.whatWentWell || '';
    document.getElementById('rrChallenges').value = rr.challenges || '';
    document.getElementById('rrKeyLearnings').value = rr.keyLearnings || '';
    document.getElementById('rrActionItems').value = rr.actionItems || '';
    document.getElementById('rrOverallReflection').value = rr.overallReflection || '';
    document.getElementById('rrImpactRating').value = rr.impactRating || '';
    document.getElementById('rrDate').value = rr.date || new Date().toISOString().split('T')[0];
  }

  openModal('reflectiveReportModal');
}

function saveReflectiveReport(e) {
  e.preventDefault();
  const type = document.getElementById('rrEntryType').value;
  const id = document.getElementById('rrEntryId').value;
  const dbKey = type === 'training' ? 'trainings' : 'visits';
  const entries = DB.get(dbKey) || [];
  const idx = entries.findIndex(e => e.id === id);
  if (idx < 0) { showToast('Entry not found', 'error'); return; }

  entries[idx].reflectiveReport = {
    whatWentWell: document.getElementById('rrWhatWentWell').value.trim(),
    challenges: document.getElementById('rrChallenges').value.trim(),
    keyLearnings: document.getElementById('rrKeyLearnings').value.trim(),
    actionItems: document.getElementById('rrActionItems').value.trim(),
    overallReflection: document.getElementById('rrOverallReflection').value.trim(),
    impactRating: document.getElementById('rrImpactRating').value,
    date: document.getElementById('rrDate').value,
    updatedAt: new Date().toISOString()
  };

  DB.set(dbKey, entries);
  if (typeof markUnsavedChanges === 'function') markUnsavedChanges();
  closeModal('reflectiveReportModal');
  if (type === 'training') renderTrainings();
  else renderVisits();
  showToast('Reflective report saved ', 'success');
}

